-- Poems batch 128
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8c63bcf8-42e3-4824-892b-207a5bfe906d','次韻蚤蚊','范成大','宋','宋诗','song-poetry','','[]','羽蟲么魔塞區寰，造化胡爲弗疾頑。',64,'全唐诗/poet.song.137000.json','["羽蟲么魔塞區寰，造化胡爲弗疾頑。", "長養汙泥草木處，縱橫大地山河間。", "夜聲雷動人力屈，秋喙花開天理還。", "但願江湖無白鳥，何須金鼎鑄神姦。"]'),
('a212f0bd-b627-4276-a83e-8c356e2f3e9f','冬至晚起枕上有懷晉陵楊使君  其一','范成大','宋','宋诗','song-poetry','','[]','新衣兒女閙燈前，夢裏莊周正栩然。',32,'全唐诗/poet.song.137000.json','["新衣兒女閙燈前，夢裏莊周正栩然。", "騎馬十年聽曉鼓，人生元有日高眠。"]'),
('d8d7a886-7e56-47fd-90bb-804ef61f118a','冬至晚起枕上有懷晉陵楊使君  其二','范成大','宋','宋诗','song-poetry','','[]','多稼亭邊有所思，冬來撚却幾行髭。',32,'全唐诗/poet.song.137000.json','["多稼亭邊有所思，冬來撚却幾行髭。", "也應坐擁黄紬被，斷角孤鴻總要詩。"]'),
('d2438f1f-2952-4d7c-8083-afee465afc7e','寒雨','范成大','宋','宋诗','song-poetry','','[]','何事冬來雨打窗，夜聲滴滴曉聲淙。',32,'全唐诗/poet.song.137000.json','["何事冬來雨打窗，夜聲滴滴曉聲淙。", "若爲化作漫天雪，徑上孤篷釣晚江。"]'),
('ae7391fc-aef5-4f59-ae35-a7e7a9ee0858','戲贈脚婆','范成大','宋','宋诗','song-poetry','','[]','日滿東窗照被堆，宿湯猶自暖如煨。',32,'全唐诗/poet.song.138000.json','["日滿東窗照被堆，宿湯猶自暖如煨。", "尺三汗脚君休笑，曾踏鞾霜待漏來。"]'),
('0f0b345d-c074-4ec7-bde7-e28438712b7b','除夜前二日夜雨','范成大','宋','宋诗','song-poetry','','[]','雪不成花夜雨來，壠頭一洗定無埃。',32,'全唐诗/poet.song.138000.json','["雪不成花夜雨來，壠頭一洗定無埃。", "小童却怕溪橋滑，明日先生合探梅。"]'),
('2830ba3f-1c50-4064-bc84-0dc9bee102c9','次韻章秀才北城新圃  其一','范成大','宋','宋诗','song-poetry','','[]','方流桃花塢，窈窕入壺天。',48,'全唐诗/poet.song.138000.json','["方流桃花塢，窈窕入壺天。", "碧城當巖岫，清灣如澗泉。", "風月欲無價，聊費四萬錢。", "雪後春事起，紅雲蜂蝶邊。"]'),
('f0902ccf-9795-4414-9108-0e992ac52413','次韻章秀才北城新圃  其二','范成大','宋','宋诗','song-poetry','','[]','西城如西塞，桃花古來多。',48,'全唐诗/poet.song.138000.json','["西城如西塞，桃花古來多。", "釣艇鱖魚肥，前身張志和。", "煙霏幾白鷺，風雨一綠蓑。", "清江韻新引，清絕勝陽阿。"]'),
('d841affe-da99-4462-83fd-0b3b97191837','夢中作','范成大','宋','宋诗','song-poetry','','[]','漠漠人間一氣平，虛無宮殿鎖飛瓊。',32,'全唐诗/poet.song.138000.json','["漠漠人間一氣平，虛無宮殿鎖飛瓊。", "碧雲萬里海光動，何處書來金鶴鳴。"]'),
('9bdaab7b-4d9e-47d8-8443-c15b363a639f','北城梅爲雪所厄','范成大','宋','宋诗','song-poetry','','[]','凍蕊粘枝瘦欲乾，新年猶未有春看。',32,'全唐诗/poet.song.138000.json','["凍蕊粘枝瘦欲乾，新年猶未有春看。", "雪花袛欲欺紅紫，不道梅花也怕寒。"]'),
('e03ba761-22e5-447b-ba3b-a9cfb4fabd5e','雪後六言二首  其一','范成大','宋','宋诗','song-poetry','','[]','雨聲和深巷屐，風力到短檠燈。',28,'全唐诗/poet.song.138000.json','["雨聲和深巷屐，風力到短檠燈。", "可惜滴殘檐雪，從教漂盡河冰。"]'),
('50098d12-7f66-4799-a48a-d81ecb5c2a4a','雪後六言二首  其二','范成大','宋','宋诗','song-poetry','','[]','歲寒破屋萬卷，風急疎窗一燈。',28,'全唐诗/poet.song.138000.json','["歲寒破屋萬卷，風急疎窗一燈。", "高卧眼生醉纈，遠遊鬚有堅冰。"]'),
('2e36e54f-240e-4a80-87ca-d956efa8eca5','元夕大風雨二絕  其一','范成大','宋','宋诗','song-poetry','','[]','東風無頼妒華年，一夜淒寒到酒邊。',32,'全唐诗/poet.song.138000.json','["東風無頼妒華年，一夜淒寒到酒邊。", "放盡珠簾遮畫炬，莫教檐雨濕青煙。"]'),
('d4f523a1-6063-442e-b122-4225701e9fc2','元夕大風雨二絕  其二','范成大','宋','宋诗','song-poetry','','[]','河傾海立夜翻盆，不獨妨燈更損春。',32,'全唐诗/poet.song.138000.json','["河傾海立夜翻盆，不獨妨燈更損春。", "凍澀笙簧猶可耐，滴皴梅頰勢須嗔。"]'),
('da1306b1-6c6a-4971-88c9-6ffeef2ef977','春懷','范成大','宋','宋诗','song-poetry','','[]','柳顰梅笑各相惱，詩債棋讎俱見尋。',32,'全唐诗/poet.song.138000.json','["柳顰梅笑各相惱，詩債棋讎俱見尋。", "莫道幽居無一事，春來風物總關心。"]'),
('34a8f9ad-dc1b-4bac-aa01-6442799abcf3','自橫塘橋過黄山','范成大','宋','宋诗','song-poetry','','[]','陣陣輕寒細馬驕，竹林茅店小帘招。',32,'全唐诗/poet.song.138000.json','["陣陣輕寒細馬驕，竹林茅店小帘招。", "東風已綠南溪水，更染溪南萬柳條。"]'),
('4d8f259a-f448-4e38-b126-79efed97cf47','次韻謝李叔玠追路送筍','范成大','宋','宋诗','song-poetry','','[]','墮地錦䙀茁，解衣溫玉姿。',48,'全唐诗/poet.song.138000.json','["墮地錦䙀茁，解衣溫玉姿。", "來償食竹債，大勝伏雌炊。", "少日羹藜子，老來煨芋師。", "盤餐登異味，指動已先知。"]'),
('b3563c86-aa02-4d6d-89ef-a6b1cdbaea41','秀州門外泊舟','范成大','宋','宋诗','song-poetry','','[]','拍岸清波撲岸埃，黑頭霜鬢幾徘徊。',32,'全唐诗/poet.song.138000.json','["拍岸清波撲岸埃，黑頭霜鬢幾徘徊。", "禾興門外官楊柳，又見扁舟上堰來。"]'),
('d0299687-0289-4498-9958-128bb5416c83','臨平道中','范成大','宋','宋诗','song-poetry','','[]','煙雨桃花夾岸栽，低低渾欲傍船來。',32,'全唐诗/poet.song.138000.json','["煙雨桃花夾岸栽，低低渾欲傍船來。", "石湖有此紅千葉，前日春寒總未開。"]'),
('95237125-4a7a-48bc-85d8-0dfebce6b669','夜過越上不得遊覽','范成大','宋','宋诗','song-poetry','','[]','王程公事兩相催，衝雨片帆連夜開。',64,'全唐诗/poet.song.138000.json','["王程公事兩相催，衝雨片帆連夜開。", "千巖萬壑在何處，山陰道中無好懷。", "豈有酒船尋賀老，興盡却能訪安道。", "鑑湖春色漫芳菲，付與青青湖畔草。"]'),
('7a74c567-b963-4102-81c1-1840f7821456','道中古意二絕  其一','范成大','宋','宋诗','song-poetry','','[]','桃李寂無言，垂楊照溪綠。',24,'全唐诗/poet.song.138000.json','["桃李寂無言，垂楊照溪綠。", "不見苧蘿人，空吟若邪曲。"]'),
('756a9d16-c330-45f1-acc6-2a63038377fc','道中古意二絕  其二','范成大','宋','宋诗','song-poetry','','[]','浣紗寂不好，辛苦觸戰箭。',24,'全唐诗/poet.song.138000.json','["浣紗寂不好，辛苦觸戰箭。", "東施無麗質，安穩嫁鄉縣。"]'),
('afc6ca4c-9c59-4b1c-8f56-df106da719de','觀禊帖有感三絕  其一','范成大','宋','宋诗','song-poetry','','[]','古人賦多情，無事輒愁苦。',24,'全唐诗/poet.song.138000.json','["古人賦多情，無事輒愁苦。", "蘭亭一觴詠，感慨乃如許。"]'),
('b2422e96-dda5-4c04-bdb8-92f5c5e60ad8','觀禊帖有感三絕  其二','范成大','宋','宋诗','song-poetry','','[]','寶章薶九泉，摹本範百世。',24,'全唐诗/poet.song.138000.json','["寶章薶九泉，摹本範百世。", "白鵝滿波間，誰識腕中意。"]'),
('5037a688-4ae0-474f-9753-9071d5649199','觀禊帖有感三絕  其三','范成大','宋','宋诗','song-poetry','','[]','三日天氣新，禊飲傳自古。',24,'全唐诗/poet.song.138000.json','["三日天氣新，禊飲傳自古。", "今人不好事，佳節棄如土。"]'),
('9661dec2-d8d8-4478-921b-99a9941af298','浙東舟中','范成大','宋','宋诗','song-poetry','','[]','處處槿樊圃，家家桃廡門。',48,'全唐诗/poet.song.138000.json','["處處槿樊圃，家家桃廡門。", "魚鹽臨水市，煙火隔江村。", "雨過張帆重，潮來汲井渾。", "彎跧短篷底，休說兩朱轓。"]'),
('cc477b2a-57e3-446f-acad-97d7bbf69f24','初赴明州','范成大','宋','宋诗','song-poetry','','[]','四征惟是欠東征，行李如今忽四明。',64,'全唐诗/poet.song.138000.json','["四征惟是欠東征，行李如今忽四明。", "海接三韓諸島近，江分七堰兩潮平。", "擬將寬大來宣詔，先趁清和去勸耕。", "頂踵國恩元未報，驅馳何敢歎勞生。"]'),
('52a6b396-e334-4599-9951-eb6a9da127ac','寄虎丘範長老','范成大','宋','宋诗','song-poetry','','[]','誰云簪紱坐成禽，亦漫爲官漫好音。',64,'全唐诗/poet.song.138000.json','["誰云簪紱坐成禽，亦漫爲官漫好音。", "身已備嘗生老病，心何曾住去來今。", "一波不動月空照，萬籟無情風自吟。", "持此東歸似同志，故應分我半山林。"]'),
('0e020b92-101e-4b1d-afc0-05ea3af37225','次韻汪仲嘉尚書喜雨  其一','范成大','宋','宋诗','song-poetry','','[]','雨雲渾似雪雲同，天意人心本自通。',32,'全唐诗/poet.song.138000.json','["雨雲渾似雪雲同，天意人心本自通。", "吏役驅驅騎馬滑，何如欹枕閉門中。"]'),
('ee2f1275-07b5-49cb-a21f-ad9ccb78e201','次韻汪仲嘉尚書喜雨  其二','范成大','宋','宋诗','song-poetry','','[]','老身窮若不須憂，未有毫分慰此州。',32,'全唐诗/poet.song.138000.json','["老身窮若不須憂，未有毫分慰此州。", "但得田間無歎息，何須地上見錢流。"]'),
('ccfcc839-f088-40b3-bcde-4190067be75a','曉起','范成大','宋','宋诗','song-poetry','','[]','窗明驚起倒裳衣，鈴索頻搖定怪遲。',32,'全唐诗/poet.song.138000.json','["窗明驚起倒裳衣，鈴索頻搖定怪遲。", "即入簿書叢裏去，少留欹枕聽黄鸝。"]'),
('f8e7a295-9d54-4734-af3a-fa136243cbba','大風','范成大','宋','宋诗','song-poetry','','[]','颶母從來海若家，青天白地忽飛沙。',32,'全唐诗/poet.song.138000.json','["颶母從來海若家，青天白地忽飛沙。", "煩將殘暑驅除盡，只莫顛狂損稻花。"]'),
('99d61650-2b82-4973-9d2e-e60ee1af133c','大黄花','范成大','宋','宋诗','song-poetry','','[]','大芋高荷半畝陰，玉英危綴碧瑶簪。',32,'全唐诗/poet.song.138000.json','["大芋高荷半畝陰，玉英危綴碧瑶簪。", "誰知一葉蓮花面，中有將軍劍戟心。"]'),
('2cc85842-e1a3-40b2-8313-fa6aee9983a9','進修堂前荷池','范成大','宋','宋诗','song-poetry','','[]','方池留水勝埋盆，露入蓮腮沁粉痕。',32,'全唐诗/poet.song.138000.json','["方池留水勝埋盆，露入蓮腮沁粉痕。", "鈴索無聲人不到，小禽飛入閙荷根。"]'),
('df3b51b3-fd65-4919-93dc-969e98486905','州宅堂前荷花','范成大','宋','宋诗','song-poetry','','[]','凌波仙子靜中芳，也带酣紅學醉粧。',64,'全唐诗/poet.song.138000.json','["凌波仙子靜中芳，也带酣紅學醉粧。", "有意十分開曉露，無情一餉斂斜陽。", "泥根玉雪元無染，風葉青葱亦自香。", "想得石湖花正好，接天雲錦畫船凉。"]'),
('d073b0f0-37a9-4169-8a6a-5098416f7fb5','新荔枝四絕  其一','范成大','宋','宋诗','song-poetry','','[]','荔浦園林瘴霧中，戎州沽酒擘輕紅。',32,'全唐诗/poet.song.138000.json','["荔浦園林瘴霧中，戎州沽酒擘輕紅。", "五年食指無占處，何意相逢萬壑東。"]'),
('6e54903b-063a-42b7-9064-3fb92e77cf13','新荔枝四絕  其二','范成大','宋','宋诗','song-poetry','','[]','海北天西兩鬢蓬，閩山猶欠一枝筇。',32,'全唐诗/poet.song.138000.json','["海北天西兩鬢蓬，閩山猶欠一枝筇。", "鄞船荔子如新摘，行脚何須更雪峰。"]'),
('a3e4cf6c-58e9-4f94-94fd-c8f0e78d358b','新荔枝四絕  其三','范成大','宋','宋诗','song-poetry','','[]','甘露凝成一顆冰，露穠冰厚更芳馨。',32,'全唐诗/poet.song.138000.json','["甘露凝成一顆冰，露穠冰厚更芳馨。", "夜凉將到星河下，擬共嫦娥鬭月明。"]'),
('a62c24e5-f5a0-4015-8b03-32fc1dbab6be','新荔枝四絕  其四','范成大','宋','宋诗','song-poetry','','[]','趠舶飛來不作難，紅塵一騎笑長安。',32,'全唐诗/poet.song.138000.json','["趠舶飛來不作難，紅塵一騎笑長安。", "孫郎皺玉無消息，先破潘郎玳瑁盤。"]'),
('53909e09-5dd0-457d-a480-ef0b808746ae','甬東道院午坐','范成大','宋','宋诗','song-poetry','','[]','一夜西風轉酒旗，午餘殘暑不多時。',64,'全唐诗/poet.song.138000.json','["一夜西風轉酒旗，午餘殘暑不多時。", "綠荷半蝕霜前葉，丹桂全封雨後枝。", "忙裏有詩償日課，老來無賦爲秋悲。", "梳頭小隸那知此，强向窗前數鬢絲。"]'),
('cbaad38d-ab7b-45ce-98d4-f6a52c63cf62','東門外觀刈熟民間租米船相銜入門喜作二絕  其一','范成大','宋','宋诗','song-poetry','','[]','菊莎杞棘爨無煙，日日文書橫索錢。',32,'全唐诗/poet.song.138000.json','["菊莎杞棘爨無煙，日日文書橫索錢。", "今日甬東官况好，東津門外看租船。"]'),
('3f498465-c24c-4c6c-97da-0fbf55b5c0ed','東門外觀刈熟民間租米船相銜入門喜作二絕  其二','范成大','宋','宋诗','song-poetry','','[]','潮到靈橋綠繞船，海邊力穡屢豐年。',32,'全唐诗/poet.song.138000.json','["潮到靈橋綠繞船，海邊力穡屢豐年。", "淡青山色深黄稻，恰似胥門九月天。"]'),
('3362a0e1-67ac-481a-9717-ca9107612653','探木犀','范成大','宋','宋诗','song-poetry','','[]','秋半秋香花信遲，攀枝擘葉看纖微。',32,'全唐诗/poet.song.138000.json','["秋半秋香花信遲，攀枝擘葉看纖微。", "昨朝尚作茶槍瘦，今雨催成粟粒肥。"]'),
('151537b4-6154-43f5-a165-d85788472c46','九月五日晴暖步後園','范成大','宋','宋诗','song-poetry','','[]','海氣烘晴入斷霞，半空雲影界山斜。',32,'全唐诗/poet.song.138000.json','["海氣烘晴入斷霞，半空雲影界山斜。", "輕羅小扇游蜂畔，只比東風有菊花。"]'),
('266c543f-d654-4426-a2a2-4e87f2eb1842','九日憶菊坡','范成大','宋','宋诗','song-poetry','','[]','菊坡長恨隔橫塘，城郭山林自不雙。',32,'全唐诗/poet.song.138000.json','["菊坡長恨隔橫塘，城郭山林自不雙。", "放棹松江花已遠，濤江之外更鄞江。"]'),
('2b534997-7bad-43de-b651-63895ef8a99e','重陽九經堂作','范成大','宋','宋诗','song-poetry','','[]','俗間佳節自匆匆，老去悲秋又客中。',64,'全唐诗/poet.song.138000.json','["俗間佳節自匆匆，老去悲秋又客中。", "青嶂捲簾三面月，黄花吹鬢幾絲風。", "十年故國新栽柳，萬里他鄉舊轉蓬。", "誰與安排今夜夢，片帆飛到小籬東。"]'),
('40d9f197-0d9e-4661-87f1-e803cd0bc78d','真瑞堂前丹桂  其一','范成大','宋','宋诗','song-poetry','','[]','血色凡花太俗生，花工新意染秋英。',32,'全唐诗/poet.song.138000.json','["血色凡花太俗生，花工新意染秋英。", "袍紅太重鞓紅淺，畫不能摹句寫成。"]'),
('658e7afe-3ada-48f5-9bba-970df6cd6e0b','真瑞堂前丹桂  其二','范成大','宋','宋诗','song-poetry','','[]','官忙風月鎮長閒，開遍香紅酒尚寒。',32,'全唐诗/poet.song.138000.json','["官忙風月鎮長閒，開遍香紅酒尚寒。", "若要與花相領略，千巖隨分有闌干。"]'),
('ff456b1a-5252-461d-9572-e207ef820917','題羔羊齋外木芙蓉','范成大','宋','宋诗','song-poetry','','[]','慵粧酣酒夕陽濃，洗盡霜痕看綺叢。',32,'全唐诗/poet.song.138000.json','["慵粧酣酒夕陽濃，洗盡霜痕看綺叢。", "綠地團花紅錦障，不知庭院有西風。"]'),
('5368e87b-f707-4431-9209-82294175d7e1','進思堂夜坐懷故山','范成大','宋','宋诗','song-poetry','','[]','塵事潮來不可推，身如病鶴强毰毸。',64,'全唐诗/poet.song.138000.json','["塵事潮來不可推，身如病鶴强毰毸。", "簿書遮斷尋詩路，風雨驚殘問月杯。", "想得竹門無客到，直須雪夜有船迴。", "鱸鄉望眼雙明處，袛欠凌霄萬仞臺。"]'),
('9fa76d80-c7fc-4c70-b723-ec18883c7058','楊少監寄西征近詩來因賦二絕爲謝詩卷第一首乃石湖作別時倡和也  其一','范成大','宋','宋诗','song-poetry','','[]','柴門重客醉中歸，尚憶揮毫索紙時。',32,'全唐诗/poet.song.138000.json','["柴門重客醉中歸，尚憶揮毫索紙時。", "何物與儂供不朽，西征卷首石湖詩。"]'),
('cb30b337-b793-475f-bf03-458cc231a3ba','楊少監寄西征近詩來因賦二絕爲謝詩卷第一首乃石湖作別時倡和也  其二','范成大','宋','宋诗','song-poetry','','[]','錦囊隨上越王臺，天海風濤亦壯哉。',32,'全唐诗/poet.song.138000.json','["錦囊隨上越王臺，天海風濤亦壯哉。", "書到嶺頭梅恰動，一枝應伴一篇來。"]'),
('d0c378e5-8fe5-4e55-a21f-075527e6203d','羔羊齋小池兩涘木芙蓉盛開有懷故園','范成大','宋','宋诗','song-poetry','','[]','洞戶掩秋深，畫橋橫晚靜。',72,'全唐诗/poet.song.138000.json','["洞戶掩秋深，畫橋橫晚靜。", "嫋嫋芙蓉風，池光弄花影。", "懷我白鷗邊，錦帳繚千頃。", "明河拍岸平，紅綠染天鏡。", "釣船無畔岸，收拾入簿領。", "牆籓束院落，寒窘令人癭。"]'),
('9b10bd0a-ec4f-443a-b422-9168bd56e342','鹿鳴席上贈貢士','范成大','宋','宋诗','song-poetry','','[]','登陸由來說四明，台星光處更魁星。',64,'全唐诗/poet.song.138000.json','["登陸由來說四明，台星光處更魁星。", "海濱二老尊周室，館下諸生右漢廷。", "秋賦重增人物志，春闈俱上佛名經。", "一飛好趁扶搖便，咫尺西興是北溟。"]'),
('558b0fc3-3a70-439a-8abd-cf04d0771eeb','大廳後堂南窗負暄','范成大','宋','宋诗','song-poetry','','[]','萬壑無聲海不波，一窗油紙暮春和。',64,'全唐诗/poet.song.138000.json','["萬壑無聲海不波，一窗油紙暮春和。", "醉眠陡覺氍毹贅，圍坐翻嫌榾柮多。", "水暖玉池添潄嚥，花生銀海費揩摩。", "端如擁褐茅檐下，袛欠烏烏擊缶歌。"]'),
('fb8ef9ea-0c83-41d8-b2b6-5eac4ff1dc66','晚步北園','范成大','宋','宋诗','song-poetry','','[]','刮地晴飆退海痕，出門無扇可障塵。',64,'全唐诗/poet.song.138000.json','["刮地晴飆退海痕，出門無扇可障塵。", "麥枯瘠土何時雪，梅糝疎林昨夜春。", "天鏡風煙疑夢事，鬢霜時節尚官身。", "裹章束带朝還暮，慚愧青鞋紫領巾。"]'),
('b69b7a5a-5723-4515-812d-0ff7dc453e23','謝賜臘藥感遇之什','范成大','宋','宋诗','song-poetry','','[]','鴻寶刀圭下九關，十年長奉璽封看。',64,'全唐诗/poet.song.138000.json','["鴻寶刀圭下九關，十年長奉璽封看。", "扶持蒲柳身猶健，收拾桑榆歲又寒。", "天地恩深雙鬢雪，山川途遠一心丹。", "疲甿疾苦今何似，拜手歸來愧伐檀。"]'),
('ff8b6efc-dc67-453e-9430-b6b197b3aff4','立春後一日作','范成大','宋','宋诗','song-poetry','','[]','浮生萬法本悠哉，大笑羲娥轉轂催。',64,'全唐诗/poet.song.138000.json','["浮生萬法本悠哉，大笑羲娥轉轂催。", "官事已邀癡作伴，春風應共老俱來。", "雲容雪意將詩問，柳眼花心待酒媒。", "九十韶光天不靳，人間笑口自難開。"]'),
('ab453b7f-5333-4669-a4ca-71833a008542','春前十日作','范成大','宋','宋诗','song-poetry','','[]','臘淺猶賒十日春，官忙長愧百年身。',64,'全唐诗/poet.song.138000.json','["臘淺猶賒十日春，官忙長愧百年身。", "雪催未動詩無力，愁遣還來酒不神。", "節物何曾欺老病，書生自慣說悲辛。", "終朝戚促成何事，今古紛紛一窖塵。"]'),
('a6e268ee-a6d9-4dd3-a366-d596d90ef324','三江亭觀雪','范成大','宋','宋诗','song-poetry','','[]','陰山陽朔雪中迴，行到天西玉作堆。',32,'全唐诗/poet.song.138000.json','["陰山陽朔雪中迴，行到天西玉作堆。", "乘興却遊東海上，白銀宮闕認蓬萊。"]'),
('422583a2-62d5-4be8-84f0-d068e9761f58','懷歸寄題小艇','范成大','宋','宋诗','song-poetry','','[]','日出塵生萬劫忙，可憐虛費隙駒光。',64,'全唐诗/poet.song.138000.json','["日出塵生萬劫忙，可憐虛費隙駒光。", "若教閒裏工夫到，始覺淡中滋味長。", "歲晚角巾思芋栗，年來手版愧耕桑。", "松風蘿月須相信，春水深時上野航。"]'),
('cc039618-7794-4d79-a9dd-956ab47f2313','雪後雨作','范成大','宋','宋诗','song-poetry','','[]','瑞葉飛來麥已青，更煩膏雨發欣榮。',32,'全唐诗/poet.song.138000.json','["瑞葉飛來麥已青，更煩膏雨發欣榮。", "東風不是厭滕六，却怕雪天容易晴。"]'),
('4cc7fd07-1740-4959-a202-723393489a5a','再雪','范成大','宋','宋诗','song-poetry','','[]','銀竹方依檐住，瑶花又入簾窺。',28,'全唐诗/poet.song.138000.json','["銀竹方依檐住，瑶花又入簾窺。", "一白本憐麥瘦，重來應爲梅遲。"]'),
('03c6a5b8-e5ad-4ad5-ba0e-f80b6314c758','立春日陪魏丞相登三江亭','范成大','宋','宋诗','song-poetry','','[]','佳節登臨始此回，聊從晻靄望蓬萊。',64,'全唐诗/poet.song.138000.json','["佳節登臨始此回，聊從晻靄望蓬萊。", "水分江北渡頭去，風自海東潮外來。", "太白天寒猶带雪，十洲池暖已浮醅。", "一尊往酹發船鼓，我亦歸帆相次開。"]'),
('2a467c88-77b9-4c5a-993c-ce3fb4b494de','寄題鹿伯可見一堂  其一','范成大','宋','宋诗','song-poetry','','[]','夢覺春闈俱轉蓬，仙凡今隔玉霄東。',32,'全唐诗/poet.song.138000.json','["夢覺春闈俱轉蓬，仙凡今隔玉霄東。", "聊攀鐵鎖問何似，豈敢避堂邀蓋公。"]'),
('ca01b5a8-21a1-4027-a0cb-5191a94097e0','寄題鹿伯可見一堂  其二','范成大','宋','宋诗','song-poetry','','[]','生來於君一歲長，決去愧我三年遲。',32,'全唐诗/poet.song.138000.json','["生來於君一歲長，決去愧我三年遲。", "今世誰不落第二，著鞭尚續堂中詩。"]'),
('a8b776c3-6cd7-40da-8b47-f7300550b160','寄題鹿伯可見一堂  其三','范成大','宋','宋诗','song-poetry','','[]','雪溪興盡船當迴，却擬登陸遊天台。',32,'全唐诗/poet.song.138000.json','["雪溪興盡船當迴，却擬登陸遊天台。", "經行見一堂前路，轉入湖山尋悞來。"]'),
('93ec9c18-86ad-45a1-923d-7bc495f18fef','將赴建康出城','范成大','宋','宋诗','song-poetry','','[]','牒訴繽紛塞甕天，經年癡坐兩三椽。',32,'全唐诗/poet.song.138000.json','["牒訴繽紛塞甕天，經年癡坐兩三椽。", "出門納納乾坤大，依舊青山繞畫船。"]'),
('b5171244-18ed-4989-88a6-cd710a6e6f8f','寺莊','范成大','宋','宋诗','song-poetry','','[]','大麥成苞小麥深，秧田水滿綠浮針。',32,'全唐诗/poet.song.138000.json','["大麥成苞小麥深，秧田水滿綠浮針。", "今年一飽全無慮，寬盡歸舟去客心。"]'),
('1c28e72f-7d9b-4efc-b7cb-668808ee449c','育王方丈','范成大','宋','宋诗','song-poetry','','[]','窗紙悲嘶萬壑風，石梁飛澗倒枯松。',32,'全唐诗/poet.song.138000.json','["窗紙悲嘶萬壑風，石梁飛澗倒枯松。", "殷勤昨夜三更雨，添作投淵雪色龍。"]'),
('5e246c1d-bcdb-4409-bf4f-d4896cb78fbe','鰻井','范成大','宋','宋诗','song-poetry','','[]','決甃神通未易論，雨聲留客夜翻盆。',32,'全唐诗/poet.song.138000.json','["決甃神通未易論，雨聲留客夜翻盆。", "不辭客路春泥滑，且足秧田舊水痕。"]'),
('d83f10ca-ed0b-451b-a423-2c8d26d589c0','妙喜泉','范成大','宋','宋诗','song-poetry','','[]','二士共談碑上法，千僧同酌沼中泉。',32,'全唐诗/poet.song.138000.json','["二士共談碑上法，千僧同酌沼中泉。", "法門泉味知多少，水桶繩頭一串穿。"]'),
('f284ca67-fd14-41e0-861a-32c26f62d3c0','明月堂','范成大','宋','宋诗','song-poetry','','[]','古來禪窟鎖巖扃，拂子崔嵬拄杖橫。',32,'全唐诗/poet.song.138000.json','["古來禪窟鎖巖扃，拂子崔嵬拄杖橫。", "塔上佛光堂上月，莫言公案不分明。"]'),
('c5a9fcd4-24bb-4045-9284-50c98715a539','自育王過天童松林三十里','范成大','宋','宋诗','song-poetry','','[]','竹輿窈窕入蕭森，逗雨梳風冷客襟。',32,'全唐诗/poet.song.138000.json','["竹輿窈窕入蕭森，逗雨梳風冷客襟。", "翠錦屠蘇三十里，不知脚底白雲深。"]'),
('f0df672d-70e2-487d-9efe-ecf77ffa106c','香山','范成大','宋','宋诗','song-poetry','','[]','抖擻軒裳一鬨塵，任教空翠滴烏巾。',32,'全唐诗/poet.song.138000.json','["抖擻軒裳一鬨塵，任教空翠滴烏巾。", "老身已到籃輿上，處處青山是故人。"]'),
('1a80c987-a411-4e15-9de0-1faed33af892','育王望海亭','范成大','宋','宋诗','song-poetry','','[]','海雲晻靄日蘢葱，案指光中萬象空。',32,'全唐诗/poet.song.138000.json','["海雲晻靄日蘢葱，案指光中萬象空。", "想見蓬萊西望眼，也應知我立長風。"]'),
('e68ff2a4-9358-4ee5-8a3c-5264ded73e97','天童三閣','范成大','宋','宋诗','song-poetry','','[]','松蘿羃天墮空翠，迎面風香三十里。',96,'全唐诗/poet.song.138000.json','["松蘿羃天墮空翠，迎面風香三十里。", "曾宮亭亭隔瑶水，碧瓦瓊榱五雲裏。", "千佛當門無半偈，聲聞未解祖師意。", "徧參踏破青鞋底，前樓後閣玲瓏起。", "閒客那知如許事，東齋聽雨爛熳睡。", "覺來一轉聊布施，普請雲堂來擬議。"]'),
('cfd6608d-f94f-4b05-9122-eeaa8a45408d','送江朝宗歸括蒼','范成大','宋','宋诗','song-poetry','','[]','半生三邂逅，相看成老翁。',144,'全唐诗/poet.song.138000.json','["半生三邂逅，相看成老翁。", "詩情故崒嵂，袖有天都峰。", "江山佳麗地，登臨苦匆匆。", "塔燈落淮水，寺樓倚霜空。", "攟拾著錦囊，撫掌夸窮工。", "歸轡不可挽，思入孤征鴻。", "洞天我昔遊，俛仰星一終。", "士友歎契闊，吏民念罷癃。", "婆娑故將軍，白髮簿書叢。", "足趼雖四方，夢寐煙雨東。", "歸田有脚力，尚往尋行蹤。", "期君斬寒藤，伴我搘枯筇。"]'),
('68dacb35-c328-4d69-b36a-6941f1c6b514','鍾山閣上望雨','范成大','宋','宋诗','song-poetry','','[]','天闊山長雨似煙，忽然飛去暗平川。',32,'全唐诗/poet.song.138000.json','["天闊山長雨似煙，忽然飛去暗平川。", "秔禾未實秈禾瘦，不用廉纖便霈然。"]'),
('a8b62d3c-85f9-4aa6-b331-2a0a17ab884e','除夜','范成大','宋','宋诗','song-poetry','','[]','婪尾杯殘雪滿簪，牀頭曆日費光陰。',64,'全唐诗/poet.song.138000.json','["婪尾杯殘雪滿簪，牀頭曆日費光陰。", "故山巧入忙中夢，新歲尤關客裏心。", "烏鵲倦時三匝繞，鷦鷯穩處一枝深。", "勞生佚老尋常事，從政那堪力不任。"]'),
('4b00a623-d97d-4a61-9211-9d5fc68681f4','元日','范成大','宋','宋诗','song-poetry','','[]','老來百味絮沾泥，期會關身尚火馳。',64,'全唐诗/poet.song.138000.json','["老來百味絮沾泥，期會關身尚火馳。", "幾夜鄉心欹枕處，今年脚力上樓時。", "酒缸幸有乾坤大，丹鼎何憂日月遲。", "莫道神仙無可學，學仙猶勝簿書癡。"]'),
('dde78846-e814-49dd-a628-272a80ba057a','體中不佳偶書','范成大','宋','宋诗','song-poetry','','[]','生平人比似維摩，試比尪孱不啻過。',64,'全唐诗/poet.song.138000.json','["生平人比似維摩，試比尪孱不啻過。", "舊摘衰髯今雪徧，頻揩病眼轉花多。", "從來世味聊復爾，此去官身如老何。", "收拾頹齡加藥餌，尚堪風月對婆娑。"]'),
('c6963f01-a7af-4076-bce9-e919d449f288','坐嘯齋書懷','范成大','宋','宋诗','song-poetry','','[]','老來窮苦事相違，兀坐鈴齋竟日癡。',64,'全唐诗/poet.song.138000.json','["老來窮苦事相違，兀坐鈴齋竟日癡。", "眼目昏緣多押字，胸襟俗爲少吟詩。", "月侵燈影吏方去，春徧梅梢官未知。", "直待食新方綬带，明朝騎馬過陵陂。"]'),
('3ede679a-35d7-4e4b-bf54-6ae8d6d1450c','寶公祈雨感應用陳申公韻賦詩爲謝','范成大','宋','宋诗','song-poetry','','[]','膴原龜坼暮春時，夾路爐薰共禱祠。',64,'全唐诗/poet.song.138000.json','["膴原龜坼暮春時，夾路爐薰共禱祠。", "喚起雲頭千嶂湧，飛來雨脚萬絲垂。", "無情梅塢猶紅綻，有意秧田盡綠滋。", "大施門開須滿願，願均此施匝天涯。"]'),
('cedde531-c12b-4f26-bd0d-4eaa3b6697db','送徐叔智運使奉祠歸吳中','范成大','宋','宋诗','song-poetry','','[]','手種湖邊花百畝，東風日夜催歸去。',96,'全唐诗/poet.song.138000.json','["手種湖邊花百畝，東風日夜催歸去。", "當年辛苦種花時，不道白頭猶未歸。", "君如肯過城南陌，但向水雲紅處覓。", "煩呼猿鶴問平安，當有畦丁解看客。", "我今江船亦欲東，檝迎楓橋成兩翁。", "壓枝萬朶雖過盡，尚及巢龜蓮葉中。"]'),
('af602e0c-3159-4042-967f-c89a7b8cf4bc','送舉老歸廬山','范成大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','二千里往回似夢，四十年今昔如浮。',32,'全唐诗/poet.song.138000.json','["二千里往回似夢，四十年今昔如浮。", "去矣莫久留桑下，歸歟來共煨芋頭。"]'),
('b7145090-ebd5-4e21-ab24-f5593051f6f2','題現老真','范成大','宋','宋诗','song-poetry','','[]','三十年來共葛藤，如今蓮社冷如冰。',32,'全唐诗/poet.song.138000.json','["三十年來共葛藤，如今蓮社冷如冰。", "茶瓜櫻筍遊山會，從此齋厨欠一僧。"]'),
('ab8ed4e7-da0b-4160-97f4-b657dc63a811','致一齋述事','范成大','宋','宋诗','song-poetry','','[]','文書煙海困浮沉，不覺盤跚百病侵。',64,'全唐诗/poet.song.138000.json','["文書煙海困浮沉，不覺盤跚百病侵。", "偶問客年驚我老，忽聞鶑語歎春深。", "今朝麥粒黄堪麫，幾日秧田綠似針。", "除却一犁春雨足，眼前無物可關心。"]'),
('e587a08b-e02d-443f-a5f7-203c83c4611d','次韻楊同年祕監見寄二首  其一','范成大','宋','宋诗','song-poetry','','[]','瘴雲嵐雨幾時歸，應把周南視九夷。',64,'全唐诗/poet.song.138000.json','["瘴雲嵐雨幾時歸，應把周南視九夷。", "舊說鬼神驚落筆，新傳狐兔駭搴旗。", "韶江石老簫音在，庾嶺梅殘驛使遲。", "自古朱絃清廟具，莫貪鵬海看天池。"]'),
('7abfc74b-05bd-4680-954c-17c0229eb386','次韻楊同年祕監見寄二首  其二','范成大','宋','宋诗','song-poetry','','[]','吾衰長愧接輿狂，忙裏何心領燕香。',64,'全唐诗/poet.song.138000.json','["吾衰長愧接輿狂，忙裏何心領燕香。", "塵土簿書憎鐵研，水雲蓑笠傲金章。", "論文無伴法孤起，訪舊有情書數行。", "何日却同湖上醉，露幃宵幄爲君張。"]'),
('f9be417b-ff1c-4139-86ba-a471e9874964','曉起信筆','范成大','宋','宋诗','song-poetry','','[]','午枕汗如洗，曉櫛氣稍蘇。',120,'全唐诗/poet.song.138000.json','["午枕汗如洗，曉櫛氣稍蘇。", "莎蛩試風露，滿意鳴相呼。", "倦客感節物，流光不躊躇。", "秋聲已如許，殘暑何足驅。", "人言今歲熱，迥與常歲殊。", "此理恐未然，豈不知頭顱。", "年年有三伏，日日非故吾。", "婆娑今尚可，後當彌不如。", "病骨須一凉，未暇惜居諸。", "坐來有清思，西風搖井梧。"]'),
('12726805-a294-4e45-a972-947442c1e4b5','送曾原伯運使歸會稽用送徐叔智韻','范成大','宋','宋诗','song-poetry','','["\u592a\u6e56"]','秧田水滿麥棲畝，勸農使者翩然去。',96,'全唐诗/poet.song.138000.json','["秧田水滿麥棲畝，勸農使者翩然去。", "去年愁苦救荒時，豈敢夢爲今日歸。", "天津橋西官柳陌，文書燈火長相覓。", "江山信美不留人，寂寞回潮工送客。", "鏡湖一曲浙河東，萬頃太湖蓑笠翁。", "願賡四愁作五詠，我所思兮思剡中。"]'),
('fead3be3-d479-419f-b312-47588ec0edb0','王南卿母輓詞','范成大','宋','宋诗','song-poetry','','[]','櫛縰稱純孝，笄珈蚤隠憂。',48,'全唐诗/poet.song.138000.json','["櫛縰稱純孝，笄珈蚤隠憂。", "病中心已化，身外世如浮。", "聞道悲風木，誰能駐壑舟。", "佳兒行古道，足以賁潛幽。"]'),
('fc1fcbc0-8691-4344-89ee-d32c5b7bc170','次韻鄭校書參議留別','范成大','宋','宋诗','song-poetry','','[]','年豐方共慶，歲晚客他之。',48,'全唐诗/poet.song.138000.json','["年豐方共慶，歲晚客他之。", "吏事朝還暮，人生合復離。", "江山殘夢破，風月片帆移。", "後會吾衰矣，桑榆一繭絲。"]'),
('2e0415ec-7e97-427e-9615-3fa1ad0d667e','重九賞心亭登高','范成大','宋','宋诗','song-poetry','','[]','憶隨書劍此徘徊，投老雙旌重把杯。',64,'全唐诗/poet.song.138000.json','["憶隨書劍此徘徊，投老雙旌重把杯。", "綠鬢風前無幾在，黄花雨後不多開。", "豐年江隴青黄徧，落日淮山紫翠來。", "飲罷此身猶是客，鄉心却附晚潮回。"]'),
('40c5502f-11a1-4494-a880-04e2bb0a6f2b','寄題王仲顯讀書樓','范成大','宋','宋诗','song-poetry','','[]','嗜書如嗜酒，知味乃篤好。',168,'全唐诗/poet.song.138000.json','["嗜書如嗜酒，知味乃篤好。", "欲辨已忘言，不爲醒者道。", "使君青箱家，文史裝懷抱。", "平生名教樂，雙旌不滿笑。", "忽乘雪溪興，來檥秦淮棹。", "丘亭客漂泊，夜夜短檠照。", "人云太癡絕，我自斲輪妙。", "今朝檣竿起，昨夢繞閤皂。", "云有百尺樓，歸寄北窗傲。", "滴露紬朱黄，拂塵靜緗縹。", "想當呻畢時，寧復羨騰趠。", "古心千載事，俗眼詎能料。", "蕭灘富還往，取友必同調。", "一張復一弛，釀秫助歌嘯。"]'),
('574f3cb9-ece8-49c1-bc62-8508c2a106a7','菊樓','范成大','宋','宋诗','song-poetry','','[]','東籬秋色照疎蕪，挽結高花不用扶。',32,'全唐诗/poet.song.138000.json','["東籬秋色照疎蕪，挽結高花不用扶。", "浄洗西風塵土面，來看金碧萬浮圖。"]'),
('584ebc8f-8302-4c1b-a18f-e6cc05009f5d','北門覆舟山道中','范成大','宋','宋诗','song-poetry','','[]','苒苒霜風掠弊貂，簿書塵外訪漁樵。',64,'全唐诗/poet.song.138000.json','["苒苒霜風掠弊貂，簿書塵外訪漁樵。", "林煙色淡如濛雨，塘水痕深似落潮。", "鴈字江天聞塞管，梅梢山路欠溪橋。", "騎馿索句當年事，歲暮騷人不自聊。"]'),
('7a505442-1c74-4351-a81c-c0bd1373f632','送郭明復寺丞守蜀州','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','士進固未易，退亦良獨難。',144,'全唐诗/poet.song.138000.json','["士進固未易，退亦良獨難。", "西州多故人，歸路常險艱。", "有道獨行意，郭舟若神仙。", "勿輕銀兔符，傾倒金貂蟬。", "唐安君昔遊，百萬蠲逋錢。", "我亦常客夢，醉歌采菱船。", "父老尚相記，况君有前緣。", "想見東西湖，恩波漲春瀾。", "此地著經濟，紗籠相後先。", "潭潭相業堂，新題我所刊。", "政爲來者地，君行豈偶然。", "去去進明德，後日五四賢。"]'),
('3d84af4f-ac12-487c-8824-593c25f04a14','元日鍾山寶公塔','范成大','宋','宋诗','song-poetry','','[]','雪後江臯未放春，老來猶駕兩朱輪。',64,'全唐诗/poet.song.138000.json','["雪後江臯未放春，老來猶駕兩朱輪。", "歸心歷歷來時路，官事驅驅病裏身。", "未暇雞窠尋古佛，且防鶴帳怨山人。", "君看王謝墩邊地，今古功名一窖塵。"]'),
('1531c33a-c1d3-43b6-b044-2f28c8e1d0e9','元日馬上二絕  其一','范成大','宋','宋诗','song-poetry','','[]','泥絮心情雪樣髯，詩囊羞澀酒杯嫌。',32,'全唐诗/poet.song.138000.json','["泥絮心情雪樣髯，詩囊羞澀酒杯嫌。", "年來萬事都消減，惟有牀頭曆日添。"]'),
('4c0503e4-5fd6-452c-94c5-1b3d9c89242e','元日馬上二絕  其二','范成大','宋','宋诗','song-poetry','','[]','筋骸全比去年非，騎吹聲中憶釣磯。',32,'全唐诗/poet.song.138000.json','["筋骸全比去年非，騎吹聲中憶釣磯。", "待得江風欺老病，何如閒健一蓑歸。"]'),
('abb5d3f3-7acc-4bfa-b79d-8d2f10068948','春晚','范成大','宋','宋诗','song-poetry','','[]','荒園蕭瑟懶追隨，舞燕啼鶑各自私。',64,'全唐诗/poet.song.138000.json','["荒園蕭瑟懶追隨，舞燕啼鶑各自私。", "窗下日長多得睡，尊前花老不供詩。", "吾衰久矣雙蓬鬢，歸去來兮一釣絲。", "想見籬東春漲動，小舟無伴柳絲垂。"]'),
('9fe2e8b0-f51c-4ece-bd5d-8c39a4d23f9c','北窗偶書呈王仲顯南卿二友','范成大','宋','宋诗','song-poetry','','[]','官居故偪仄，北窗誰所開。',120,'全唐诗/poet.song.138000.json','["官居故偪仄，北窗誰所開。", "胡牀憩午暑，簾影久徘徊。", "高槐忽低昂，知有好風來。", "須臾墮几席，篆香小飛灰。", "病翁亦披襟，月露裝奇懷。", "壠頭暴背耘，永晝婦子偕。", "不辭夢山裂，田水如潑醅。", "去年豈堪說，稻根已浮埃。", "使君坐侯宅，窗間即凉臺。", "何敢訴苦熱，灑然助心齋。"]'),
('43008eb2-9205-4b61-a4c8-7df84599805b','中秋清暉閣靜坐因思前二年石湖四明賞月','范成大','宋','宋诗','song-poetry','','[]','前年銀界接天迷，去歲金盤湧海低。',32,'全唐诗/poet.song.138000.json','["前年銀界接天迷，去歲金盤湧海低。", "漂泊相逢重一笑，秦淮東畔女牆西。"]'),
('81e2528a-d112-4446-9c32-84b1eb6691ec','玉麟堂會諸司觀牡丹酴醿三絕  其一','范成大','宋','宋诗','song-poetry','','[]','東風微峭護餘春，紅紫香中酒自溫。',32,'全唐诗/poet.song.138000.json','["東風微峭護餘春，紅紫香中酒自溫。", "不用忙催銀燭上，酴醿如雪照黄昏。"]'),
('ed402822-506b-44c9-973f-325b55fddc56','玉麟堂會諸司觀牡丹酴醿三絕  其二','范成大','宋','宋诗','song-poetry','','[]','洛園姚魏碧雲愁，風物江東亦上游。',32,'全唐诗/poet.song.138000.json','["洛園姚魏碧雲愁，風物江東亦上游。", "憶起遨頭八年夢，彭州花檻滿西樓。"]'),
('6a06b195-b79e-427a-a7e7-dda2bdfb3e3e','玉麟堂會諸司觀牡丹酴醿三絕  其三','范成大','宋','宋诗','song-poetry','','[]','莫向花前惜酒杯，一年一度有花開。',32,'全唐诗/poet.song.138000.json','["莫向花前惜酒杯，一年一度有花開。", "浮生滿百今强半，歲歲看花得幾回。"]'),
('2b744953-7dc8-4394-bbde-1ae2f1c62259','重九獨坐玉麟堂','范成大','宋','宋诗','song-poetry','','[]','江上西風動所思，又將清賞負東籬。',64,'全唐诗/poet.song.138000.json','["江上西風動所思，又將清賞負東籬。", "年年客路黄花酒，日日鄉心白鴈詩。", "籠月秦淮無舊曲，馳煙鍾阜有新移。", "人生笑口真稀闊，況值官忙閔雨時。"]'),
('e5fb8e63-8dd0-4248-8625-0624a8e421bc','次韻舉老見嘲未歸石湖','范成大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','半世吟客舍柳，長年憶後園花。',28,'全唐诗/poet.song.138000.json','["半世吟客舍柳，長年憶後園花。", "爲報廬山莫笑，雲丘今屬誰家。"]'),
('b714a7bf-1648-4e72-ac76-20d27819f3e6','次韻曾仲躬侍郎同登伏龜樓二絕  其一','范成大','宋','宋诗','song-poetry','','[]','带束江淮翠岫圍，掌窺臺殿碧鱗差。',32,'全唐诗/poet.song.138000.json','["带束江淮翠岫圍，掌窺臺殿碧鱗差。", "劉郎句裏登臨眼，壓倒三江二水詩。"]'),
('9c3e29ea-52db-4278-b63c-434e7713455f','次韻曾仲躬侍郎同登伏龜樓二絕  其二','范成大','宋','宋诗','song-poetry','','[]','古來遊客謾西東，領會誰如我與公。',32,'全唐诗/poet.song.138000.json','["古來遊客謾西東，領會誰如我與公。", "露坐繩牀天不盡，絕勝簾雨棟雲中。"]'),
('0b66e602-991c-464b-92dc-b1f2b7028183','題李雲叟畫軸兼寄江安楊簡卿明府二絕  其一','范成大','宋','宋诗','song-poetry','','[]','蒼煙枯木共荒寒，籬落堤灣洶漲湍。',32,'全唐诗/poet.song.138000.json','["蒼煙枯木共荒寒，籬落堤灣洶漲湍。", "歸路宛然歸未得，閒將李叟畫圖看。"]'),
('6f175fa9-8a2f-431a-ab53-f4311a55e87f','題李雲叟畫軸兼寄江安楊簡卿明府二絕  其二','范成大','宋','宋诗','song-poetry','','[]','新圖來自雪邊州，皴石枯槎筆最遒。',32,'全唐诗/poet.song.138000.json','["新圖來自雪邊州，皴石枯槎筆最遒。", "明府能詩如此畫，爲渠題作小營丘。"]'),
('53a11c39-6d8b-4bff-a1ee-2cc1724d7458','晨出蔣山道中','范成大','宋','宋诗','song-poetry','','[]','霜痕如雨沁東郊，樂歲家家一把茅。',64,'全唐诗/poet.song.138000.json','["霜痕如雨沁東郊，樂歲家家一把茅。", "故國丘陵多麥壠，新晴籬落有梅梢。", "小山何在應招隠，北嶺如今已獻嘲。", "歸計未成聊琢玉，飄颻風袖作推敲。"]'),
('3ea75aa6-17b9-410e-ae35-052027c33245','有感今昔二首  其一','范成大','宋','宋诗','song-poetry','','[]','陽春白雪雅音希，俚耳冬烘輒笑嗤。',64,'全唐诗/poet.song.138000.json','["陽春白雪雅音希，俚耳冬烘輒笑嗤。", "麋見麗姬翻決驟，鳥聞韶樂却憂悲。", "爛奚輕薄人何敢，伏獵荒唐自不知。", "蚓竅蠅鳴莫嘲誚，彭亨菌蠢正當時。"]'),
('bd9ca6ae-e850-4259-b8e5-84b834b3c732','有感今昔二首  其二','范成大','宋','宋诗','song-poetry','','[]','飄風驟雨謾驚春，掃蕩何煩臂屈伸。',64,'全唐诗/poet.song.138000.json','["飄風驟雨謾驚春，掃蕩何煩臂屈伸。", "天識不衷宜不恕，神歆非類即非仁。", "休讎地下枯魚骨，且鬭尊前健犢身。", "靜看可憐還可笑，香山寧是幸災人。"]'),
('4284d9c6-b104-4109-abfc-87859110d727','種竹歎向在成都種竹滿西園偶苦寒疾朅來金陵復種繞池未幾以眩卧閤家人子遂謂不當種竹其說甚可怪歎口占此詩','范成大','宋','宋诗','song-poetry','','[]','宣華種萬竿，寒疾適相值。',96,'全唐诗/poet.song.138000.json','["宣華種萬竿，寒疾適相值。", "玉麟種千竿，偶復須藥餌。", "僮奴狃今昨，競道竹相祟。", "如將聖作狂，似以儒爲戲。", "此君來聲冤，林神亦短氣。", "我夢不平鳴，霍然推枕起。", "明當還石湖，賸種千畝地。", "未論比封君，且用執讒喙。"]'),
('628618de-4cbd-45f5-8e27-392ae9155e67','公退書懷','范成大','宋','宋诗','song-poetry','','[]','昨者騰章奏發倉，今茲飛檄議驅蝗。',64,'全唐诗/poet.song.138000.json','["昨者騰章奏發倉，今茲飛檄議驅蝗。", "四無告者僅一飽，七不堪中仍百忙。", "皦日自能臨俯仰，浮雲寧解制行藏。", "求田問舍亦何有，歲晚倦遊思故鄉。"]'),
('3c399b76-84d7-4aa8-aec7-8fcd4a339ea6','初秋二首  其一','范成大','宋','宋诗','song-poetry','','[]','急雨過窗紙，新凉生簟藤。',24,'全唐诗/poet.song.138000.json','["急雨過窗紙，新凉生簟藤。", "蹣跚老鈴下，來炷壁間燈。"]'),
('01e65711-2e4f-4c49-a49b-a3b86531a865','初秋二首  其二','范成大','宋','宋诗','song-poetry','','[]','壯歲故多病，老年知不堪。',24,'全唐诗/poet.song.138000.json','["壯歲故多病，老年知不堪。", "何須看公案，只此是真參。"]'),
('96b67bb3-a361-48a8-8b71-611b5d3081dd','蝙蝠','范成大','宋','宋诗','song-poetry','','[]','伏翼昏飛急，營營定苦饑。',24,'全唐诗/poet.song.138000.json','["伏翼昏飛急，營營定苦饑。", "聚蚊充口腹，生汝亦奚爲。"]'),
('2c826fd8-33d6-4a78-8009-2b19eef94156','蛩','范成大','宋','宋诗','song-poetry','','[]','壁下秋蟲語，一蛩鳴獨雄。',24,'全唐诗/poet.song.138000.json','["壁下秋蟲語，一蛩鳴獨雄。", "自然遭跡捕，窘束入雕籠。"]'),
('c09230da-caf6-4509-b5f9-e0e6a5926a96','四花','范成大','宋','宋诗','song-poetry','','[]','素馨間末利，木犀和玉簪。',24,'全唐诗/poet.song.138000.json','["素馨間末利，木犀和玉簪。", "醫來都屏去，頭眩怕香侵。"]'),
('fd6c68f9-4847-4102-88dc-04c88f001da4','謝範老問病','范成大','宋','宋诗','song-poetry','','[]','三椽一席度秋冬，造化兒嬉困此翁。',64,'全唐诗/poet.song.138000.json','["三椽一席度秋冬，造化兒嬉困此翁。", "帖有王書難治眩，文如陳檄不驅風。", "骨枯似枿膚如腊，髮織成氈鬢作蓬。", "點檢病身還一笑，本來四大滿虛空。"]'),
('54c08d76-d239-4c33-8d08-6e77f6aa8fa1','二偈呈似壽老  其一','范成大','宋','宋诗','song-poetry','','[]','法法剎那無住，云何見在去來。',28,'全唐诗/poet.song.138000.json','["法法剎那無住，云何見在去來。", "若覓三心不見，便從不見打開。"]'),
('94472346-15aa-45b7-b251-a14fdcc8ea03','二偈呈似壽老  其二','范成大','宋','宋诗','song-poetry','','[]','孟說所過者化，莊云相代乎前。',28,'全唐诗/poet.song.138000.json','["孟說所過者化，莊云相代乎前。", "何處安身立命，饑餐渴飲困眠。"]'),
('47023f4d-cb6c-4992-b946-1c6c2642af6a','諾惺菴枕上','范成大','宋','宋诗','song-poetry','','[]','噩夢驚回曉枕寒，青燈猶照藥爐邊。',32,'全唐诗/poet.song.138000.json','["噩夢驚回曉枕寒，青燈猶照藥爐邊。", "紙窗弄色如朧月，又了浮生一夜眠。"]'),
('08ba078b-3439-430a-adb3-b54e86e2b293','癸卯除夜聊復爾齋偶題','范成大','宋','宋诗','song-poetry','','[]','五夜燈花重，東風角韻來。',96,'全唐诗/poet.song.138000.json','["五夜燈花重，東風角韻來。", "雪慳衣未纊，春早句多梅。", "寂歷羅門亞，溫黁藥鼎煨。", "老嫌新歲換，病喜舊星回。", "鬰壘先題版，屠蘇後把杯。", "書扉無健筆，爆竹有寒灰。", "餳楪牙難膠，椒盤眼倦開。", "陳人仍憊卧，身世兩悠哉。"]'),
('1c3455c6-618f-4aa1-a372-1d8e247e7313','甲辰人日病中吟六言六首以自嘲  其一','范成大','宋','宋诗','song-poetry','','[]','攢眉輒作山字，啾耳惟聞水聲。',28,'全唐诗/poet.song.138000.json','["攢眉輒作山字，啾耳惟聞水聲。", "人應見憐久病，我亦自厭餘生。"]'),
('377e730b-2034-4350-9da2-528a2e51ba38','甲辰人日病中吟六言六首以自嘲  其二','范成大','宋','宋诗','song-poetry','','[]','目慌慌蟻旋磨，頭岑岑鼇負山。',28,'全唐诗/poet.song.138000.json','["目慌慌蟻旋磨，頭岑岑鼇負山。", "筆牀久已均伏，藥鼎何時丐閒。"]'),
('3e99607b-f788-451b-92dd-4e45064846c4','甲辰人日病中吟六言六首以自嘲  其三','范成大','宋','宋诗','song-poetry','','[]','政爾榮枯衛澀，剛云人厄天窮。',28,'全唐诗/poet.song.138000.json','["政爾榮枯衛澀，剛云人厄天窮。", "歸咎四衝臨歲，乞憐九曜過宮。"]'),
('4274b670-d5f4-4005-8abc-1b8d2dee7074','甲辰人日病中吟六言六首以自嘲  其四','范成大','宋','宋诗','song-poetry','','[]','復古既愆七日，泰來惟候三陽。',28,'全唐诗/poet.song.138000.json','["復古既愆七日，泰來惟候三陽。", "曆日今頒寅正，占星更候農祥。"]'),
('492cdb1a-5dfe-46b3-bdef-0fa0739a1d60','甲辰人日病中吟六言六首以自嘲  其五','范成大','宋','宋诗','song-poetry','','[]','有日猶嫌開牖，無風不敢上簾。',28,'全唐诗/poet.song.138000.json','["有日猶嫌開牖，無風不敢上簾。", "報國丹心何似，夢中抵掌掀髯。"]'),
('ab48462f-6175-40de-a467-c898919c8435','甲辰人日病中吟六言六首以自嘲  其六','范成大','宋','宋诗','song-poetry','','[]','壯歲喜新節物，老來惜舊年華。',28,'全唐诗/poet.song.138000.json','["壯歲喜新節物，老來惜舊年華。", "病後都盧不問，家人時換瓶花。"]'),
('9be3431c-3d85-4167-9e8e-a180eb895829','正月九日雪霰後大雨二首  其一','范成大','宋','宋诗','song-poetry','','[]','夜霰三更碎瓦，晝冥一陣翻盆。',28,'全唐诗/poet.song.138000.json','["夜霰三更碎瓦，晝冥一陣翻盆。", "頼是梅花已過，不然皴玉誰溫。"]'),
('8ef3db65-faa5-4aa1-b824-83803897ca21','正月九日雪霰後大雨二首  其二','范成大','宋','宋诗','song-poetry','','[]','黄昏簷溜垂瀑，清曉屐聲滿門。',28,'全唐诗/poet.song.138000.json','["黄昏簷溜垂瀑，清曉屐聲滿門。", "湖光萬頃何似，小沼先吹縠紋。"]'),
('0ed65dfc-d493-4cfc-82a2-e63251c7739d','正月十日夜大雷震二首  其一','范成大','宋','宋诗','song-poetry','','[]','阿香真是健婦，夜半鼓行疾驅。',28,'全唐诗/poet.song.138000.json','["阿香真是健婦，夜半鼓行疾驅。", "直恐南山破碎，絕憐窗紙枝梧。"]'),
('bb75fcb1-fa61-40fb-af49-f7e38569b820','正月十日夜大雷震二首  其二','范成大','宋','宋诗','song-poetry','','[]','人言有物司鼓，春到揚桴發聲。',28,'全唐诗/poet.song.138000.json','["人言有物司鼓，春到揚桴發聲。", "但要蟄蟲啟戶，何須一許震驚。"]'),
('8740b8fd-1a00-4ec7-bb8a-793933f3eb32','吳燈兩品最高','范成大','宋','宋诗','song-poetry','','[]','鏤冰影裏百千光，剪綵毬中一萬窗。',32,'全唐诗/poet.song.138000.json','["鏤冰影裏百千光，剪綵毬中一萬窗。", "不是齊人誇管晏，吳中風物竟難雙。"]'),
('952d4745-0733-47c5-8a56-aacae32fb8b7','燈夕懷廣蜀舊事','范成大','宋','宋诗','song-poetry','','[]','灕水橋西列炬香，少城樓下變燈忙。',32,'全唐诗/poet.song.138000.json','["灕水橋西列炬香，少城樓下變燈忙。", "兒嬉萬里客程遠，老懶一龕春夢長。"]'),
('eb14aef6-aa80-47f1-906b-b2ad2968ca11','上元紀吳中節物俳諧體三十二韻','范成大','宋','宋诗','song-poetry','','[]','斗野豐年屢，吳臺樂事并。',288,'全唐诗/poet.song.138000.json','["斗野豐年屢，吳臺樂事并。", "酒壚先疊鼓，燈市蚤投瓊。", "價喜膏油賤，祥占雨雪晴。", "篔簹仙子洞，菡萏化人城。", "檣炬疑龍見，橋星訝鵲成。", "小家厖獨踞，高閈鹿雙撐。", "屏展輝雲母，簾垂晃水精。", "萬窗花眼密，千隙玉虹明。", "薝蔔丹房挂，葡萄綠蔓縈。", "方縑繙史冊，圓魄綴門衡。", "擲燭騰空穩，推毬滾地輕。", "映光魚隠見，轉影騎縱橫。", "輕薄行歌過，顛狂社舞呈。", "村田蓑笠野，街市管絃清。", "里巷分題句，官曹別扁門。", "旱船遥似泛，水儡近如生。", "鉗赭裝牢戶，嘲嗤繪樂棚。", "堵觀瑶席隘，喝道綺叢爭。", "禁鑰通三鼓，歸鞭任五更。", "桑蠶春繭勸，花蝶夜蛾迎。", "鳬子描丹筆，鵝毛剪雪英。", "寶糖珍粔籹，烏膩美飴餳。", "撚粉團欒意，熬稃腷膊聲。", "筳篿巫志怪，香火婢輸誠。"]'),
('70b0e28e-b5a6-4bfb-906d-922d10df33fd','雪寒探梅','范成大','宋','宋诗','song-poetry','','[]','酸風如箭莫憑闌，凍合橫枝雪未乾。',32,'全唐诗/poet.song.138000.json','["酸風如箭莫憑闌，凍合橫枝雪未乾。", "吳下得春元自晚，那堪天與十分寒。"]'),
('31d67acb-01bf-42de-9337-c6a38c59a15a','曉枕三首  其一','范成大','宋','宋诗','song-poetry','','[]','煮湯聽成萬籟，添被知是五更。',28,'全唐诗/poet.song.138000.json','["煮湯聽成萬籟，添被知是五更。", "陸續滿城鐘動，須臾後巷雞鳴。"]'),
('2bc8dfff-5814-4ebe-b64d-e508335fff45','曉枕三首  其二','范成大','宋','宋诗','song-poetry','','[]','卧聞赤脚鼾息，樂哉栩栩蘧蘧。',28,'全唐诗/poet.song.138000.json','["卧聞赤脚鼾息，樂哉栩栩蘧蘧。", "病夫心口相語，何日佳眠似渠。"]'),
('a4b9419b-798d-488f-8823-401c0486fb9b','曉枕三首  其三','范成大','宋','宋诗','song-poetry','','[]','舒慘常隨天氣，關心窗暗窗明。',28,'全唐诗/poet.song.138000.json','["舒慘常隨天氣，關心窗暗窗明。", "日晏扶頭未起，喚人先問陰晴。"]'),
('9f7a758c-3428-472c-8112-6b0cd708c52b','不寐','范成大','宋','宋诗','song-poetry','','[]','春宵似暖非暖，曉夢欲成未成。',28,'全唐诗/poet.song.138000.json','["春宵似暖非暖，曉夢欲成未成。", "風竹時驚雀噪，月窗誰伴梅橫。"]'),
('cefc242a-ee75-42f0-bc25-e3422ca62d04','戲書二首  其一','范成大','宋','宋诗','song-poetry','','[]','長病人嫌理亦宜，吾今有計可扶衰。',32,'全唐诗/poet.song.138000.json','["長病人嫌理亦宜，吾今有計可扶衰。", "煩君舁著山深處，恐有黄龍浴水醫。"]'),
('45e2245a-ed4e-4fc7-a705-8509da7961de','戲書二首  其二','范成大','宋','宋诗','song-poetry','','[]','羣兒欺老少陵窮，口燥脣乾髮漫衝。',32,'全唐诗/poet.song.138000.json','["羣兒欺老少陵窮，口燥脣乾髮漫衝。", "顛沛須臾猶執禮，古來惟有一高共。"]'),
('dc8f3688-5458-4699-9df1-bd7fdb436218','耳鳴','范成大','宋','宋诗','song-poetry','','[]','風號高木水翻洪，歷歷音聞不是聾。',32,'全唐诗/poet.song.138000.json','["風號高木水翻洪，歷歷音聞不是聾。", "一任大千都震吼，便從卷葉證圓通。"]'),
('ab52112e-8f3f-4a90-a9af-3b6e3a1bdfbf','案上梅花二首  其一','范成大','宋','宋诗','song-poetry','','[]','南坡玉雪萬花團，舊約東風載酒看。',32,'全唐诗/poet.song.138000.json','["南坡玉雪萬花團，舊約東風載酒看。", "冷落銅瓶一枝亞，今年天女亦酸寒。"]'),
('82218877-6540-4647-aa39-182e23c73537','案上梅花二首  其二','范成大','宋','宋诗','song-poetry','','[]','地爐火煖日烘窗，一夜花鬚半吐黄。',32,'全唐诗/poet.song.138000.json','["地爐火煖日烘窗，一夜花鬚半吐黄。", "鼻觀圓通熏百和，博山三夕罷燒香。"]'),
('f430452c-f12c-4a8b-85b7-772fa3cbaf3a','古梅二首  其一','范成大','宋','宋诗','song-poetry','','[]','孤標元不鬭芳菲，雨瘦風皴老更奇。',32,'全唐诗/poet.song.138000.json','["孤標元不鬭芳菲，雨瘦風皴老更奇。", "壓倒嫩條千萬蕊，只消疎影兩三枝。"]'),
('d6b01003-d49c-45c6-adf7-19af38edee2e','古梅二首  其二','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','誰似西湖處士才，詩中籬落久塵埃。',32,'全唐诗/poet.song.138000.json','["誰似西湖處士才，詩中籬落久塵埃。", "陸郎舊有梅花課，未見今年句子來。"]'),
