('84ccca61-26e2-4a48-91af-58eadaec7c97','題請息齋六言十首  其二','范成大','宋','宋诗','song-poetry','','[]','多謝紛紛雲雨，相忘渺渺江湖。',28,'全唐诗/poet.song.138000.json','["多謝紛紛雲雨，相忘渺渺江湖。", "坐隅但忌占鵩，屋上何煩譽烏。"]'),
('b04608f2-8ef2-4027-8a08-8e92978602d7','題請息齋六言十首  其三','范成大','宋','宋诗','song-poetry','','[]','灧澦年年似馬，太行日日摧車。',28,'全唐诗/poet.song.138000.json','["灧澦年年似馬，太行日日摧車。", "笑中恐有義甫，泣裏難防叔魚。"]'),
('7b58cdbc-7e35-4bc8-91fd-3f5a73b2f6cf','題請息齋六言十首  其四','范成大','宋','宋诗','song-poetry','','[]','見影蜮猶鉍鉍，聞聲厖尚狺狺。',28,'全唐诗/poet.song.138000.json','["見影蜮猶鉍鉍，聞聲厖尚狺狺。", "問誰毛生名紙，知我角出車輪。"]'),
('69844817-f2e8-415e-b4cc-0713a256c85e','題請息齋六言十首  其五','范成大','宋','宋诗','song-poetry','','[]','不惜人扶難拜，非關我醉欲眠。',28,'全唐诗/poet.song.138000.json','["不惜人扶難拜，非關我醉欲眠。", "勞君敬枯木耳，恐汝見濕灰焉。"]'),
('8387bece-d02f-4334-8e27-d77697bb6ebf','題請息齋六言十首  其六','范成大','宋','宋诗','song-poetry','','[]','稅駕今吾將老，結廬此地不喧。',28,'全唐诗/poet.song.138000.json','["稅駕今吾將老，結廬此地不喧。", "恐妨蝴蝶同夢，笑倩顛當守門。"]'),
('fb39fe34-4f06-439b-b3c2-c86d956cc3cc','題請息齋六言十首  其七','范成大','宋','宋诗','song-poetry','','[]','口邊一任醭去，鼻孔慵將涕收。',28,'全唐诗/poet.song.138000.json','["口邊一任醭去，鼻孔慵將涕收。", "閒門冷落車轍，空室團欒話頭。"]'),
('f939f412-dcc2-402a-939b-0c32732980b1','題請息齋六言十首  其八','范成大','宋','宋诗','song-poetry','','[]','冷煖舊雨今雨，是非一波萬波。',28,'全唐诗/poet.song.138000.json','["冷煖舊雨今雨，是非一波萬波。", "壁下禪枯達磨，室中病著維摩。"]'),
('21ea4b9f-a336-4911-bb0f-77482dd8a6fb','題請息齋六言十首  其九','范成大','宋','宋诗','song-poetry','','[]','親戚自有情話，來往都無雜言。',28,'全唐诗/poet.song.138000.json','["親戚自有情話，來往都無雜言。", "酒熟徑須相報，文成聊與細論。"]'),
('dfb04519-5e8c-4c39-9c8f-eb8cb76e30ed','題請息齋六言十首  其一○','范成大','宋','宋诗','song-poetry','','[]','園丁以時白事，山客終日相陪。',28,'全唐诗/poet.song.138000.json','["園丁以時白事，山客終日相陪。", "竹比平安報到，花依次第折來。"]'),
('64d498d3-6387-4a82-a086-6fdd577fa28b','送劉唐卿戶曹擢第西歸六首  其一','范成大','宋','宋诗','song-poetry','','[]','摩挲漢柱愴分襟，邂逅吳船喜盍簪。',32,'全唐诗/poet.song.138000.json','["摩挲漢柱愴分襟，邂逅吳船喜盍簪。", "別久十年知幾夢，情親萬里只初心。"]'),
('a0a2b4c8-b2ee-4c89-8187-6234211b7674','送劉唐卿戶曹擢第西歸六首  其二','范成大','宋','宋诗','song-poetry','','[]','學道何關紫與青，發身聊假佛名經。',32,'全唐诗/poet.song.138000.json','["學道何關紫與青，發身聊假佛名經。", "歸來解盡程書縛，千古文章似建瓴。"]'),
('4e5b345a-00e4-444e-95e5-4ee3dda417b1','送劉唐卿戶曹擢第西歸六首  其三','范成大','宋','宋诗','song-poetry','','[]','槐黄燈火困豪英，此去書窗得此生。',32,'全唐诗/poet.song.138000.json','["槐黄燈火困豪英，此去書窗得此生。", "學力根深方蔕固，功名水到自渠成。"]'),
('eae183c3-4a58-4433-9dba-7a445e2ea5b2','送劉唐卿戶曹擢第西歸六首  其四','范成大','宋','宋诗','song-poetry','','[]','中年親友惜分離，況我身兼老病衰。',32,'全唐诗/poet.song.138000.json','["中年親友惜分離，況我身兼老病衰。", "餘景庶幾猶及見，登瀛召客過門時。"]'),
('760411e6-2180-47d8-91cb-dfbf3398086d','送劉唐卿戶曹擢第西歸六首  其五','范成大','宋','宋诗','song-poetry','','[]','我識岷峨最上頭，當年脚力與雲浮。',32,'全唐诗/poet.song.138000.json','["我識岷峨最上頭，當年脚力與雲浮。", "兩山父老如相問，一席三椽正卧遊。"]'),
('a74ea42a-71de-4553-aef0-c064828f1645','送劉唐卿戶曹擢第西歸六首  其六','范成大','宋','宋诗','song-poetry','','[]','四海西州舊故多，煩君問訊各如何。',32,'全唐诗/poet.song.138000.json','["四海西州舊故多，煩君問訊各如何。", "心期本自無南北，萬里天波一月波。"]'),
('88366b31-3d25-44f6-935d-62d70eead3b5','富順楊商卿使君曏與余相別于瀘之合江渺然再會之期後九年廼訪余吳門則喜可知也今復分袂更增惘然病中强書數語送之','范成大','宋','宋诗','song-poetry','','[]','合江縣下初語離，共說再會知何時。',128,'全唐诗/poet.song.138000.json','["合江縣下初語離，共說再會知何時。", "壽櫟堂前哄一笑，人生聚散真難料。", "青燈話舊語未終，船頭疊鼓帆爭風。", "草草相逢復相送，直恐送迎皆夢中。", "昨聞親上安邊奏，玉階從容移禁漏。", "天香懷袖左魚符，歸作雙親千歲壽。", "我今老病塘蒲衰，君歸報政還復來。", "萬里儻容明月共，更期後夢如今夢。"]'),
('72232081-d76e-402e-bda2-955ecb08ac5d','久病或勸勉强遊適吟四絕答之  其一','范成大','宋','宋诗','song-poetry','','[]','風月箇中老子，江湖之上散人。',28,'全唐诗/poet.song.138000.json','["風月箇中老子，江湖之上散人。", "化鑪苦靳清福，環堵閒拋好春。"]'),
('0648250e-6a31-474a-82be-8bef838752db','久病或勸勉强遊適吟四絕答之  其二','范成大','宋','宋诗','song-poetry','','[]','鶴怨久迴俗駕，鷗盟誰主載書。',28,'全唐诗/poet.song.138000.json','["鶴怨久迴俗駕，鷗盟誰主載書。", "一丘一壑謝汝，三歲三秋望予。"]'),
('ccbeb1ac-2e86-4c82-a199-c9e9fac159c4','久病或勸勉强遊適吟四絕答之  其三','范成大','宋','宋诗','song-poetry','','[]','捫蝨即是忙事，驅蠅豈非褊心。',28,'全唐诗/poet.song.138000.json','["捫蝨即是忙事，驅蠅豈非褊心。", "香煖香寒功課，窗明窗暗光陰。"]'),
('7ec19d7f-f0ea-43b5-afb2-b845ac6aa2ee','久病或勸勉强遊適吟四絕答之  其四','范成大','宋','宋诗','song-poetry','','[]','羸如蓐婦多忌，倦似田翁作勞。',28,'全唐诗/poet.song.138000.json','["羸如蓐婦多忌，倦似田翁作勞。", "玩具僧梳刖屨，歡悰丁尾龜毛。"]'),
('f981afdc-5c7a-4827-893b-7a16ff018d3b','初秋閒記園池草木五首  其一','范成大','宋','宋诗','song-poetry','','[]','茙葵爛紫終陋，薝蔔嫣黄亦香。',28,'全唐诗/poet.song.138000.json','["茙葵爛紫終陋，薝蔔嫣黄亦香。", "醫俗賸延竹色，療愁催拆萱房。"]'),
('de27fbb3-376c-451c-998f-ec552cfa1141','初秋閒記園池草木五首  其二','范成大','宋','宋诗','song-poetry','','[]','牛牽碧蔓自繞，雞聳朱冠欲爭。',28,'全唐诗/poet.song.138000.json','["牛牽碧蔓自繞，雞聳朱冠欲爭。", "菱葩可範伯雅，蓼節偏宜麴生。"]'),
('db1b6426-4828-4bf7-9b22-214076d0d9e6','初秋閒記園池草木五首  其三','范成大','宋','宋诗','song-poetry','','[]','旱地蓮花嬌小，水盆梔子幽芳。',28,'全唐诗/poet.song.138000.json','["旱地蓮花嬌小，水盆梔子幽芳。", "薇帳半年春艷，桂叢四季秋香。"]'),
('20ae019e-08eb-4b66-a6ae-7d2021612c03','初秋閒記園池草木五首  其四','范成大','宋','宋诗','song-poetry','','[]','醉憐金琖齊側，卧看玉簪對橫。',28,'全唐诗/poet.song.138000.json','["醉憐金琖齊側，卧看玉簪對橫。", "腥水留灌末利，結香旋薰素馨。"]'),
('0fa722d4-04e2-4f6a-8a9d-7acc75b45953','初秋閒記園池草木五首  其五','范成大','宋','宋诗','song-poetry','','[]','玉菡化生稚子，碧枝視現聲聞。',28,'全唐诗/poet.song.138000.json','["玉菡化生稚子，碧枝視現聲聞。", "馬齒任藏汞冷，鴻頭自勝硫溫。"]'),
('fa2e3440-8f7b-4c90-9b77-5888de2a0866','巖桂三首  其一','范成大','宋','宋诗','song-poetry','','[]','風簾疎爽月徘徊，悵望家人把酒杯。',32,'全唐诗/poet.song.138000.json','["風簾疎爽月徘徊，悵望家人把酒杯。", "病著幽窗知幾日，瓶花兩見木犀開。"]'),
('91405d2f-ca48-4d15-aac1-3b838ba14fd3','巖桂三首  其二','范成大','宋','宋诗','song-poetry','','[]','越城芳徑手親栽，紅淺黄深次第開。',32,'全唐诗/poet.song.138000.json','["越城芳徑手親栽，紅淺黄深次第開。", "不用小山招隠賦，身如强健日千迴。"]'),
('2243a948-bb68-4369-8b26-634fb5162d06','巖桂三首  其三','范成大','宋','宋诗','song-poetry','','[]','一株蕭索倚宣華，東苑香風屬內家。',32,'全唐诗/poet.song.138000.json','["一株蕭索倚宣華，東苑香風屬內家。", "丹碧屠蘇銀燭照，平生奇絕象山花。"]'),
('d3143018-b254-4a04-92c2-0e0270615536','中秋無月三首  其一','范成大','宋','宋诗','song-poetry','','[]','兒女無悰坐客稀，今年孤負隔年期。',32,'全唐诗/poet.song.138000.json','["兒女無悰坐客稀，今年孤負隔年期。", "誰從天上牢遮月，不管人間大欠詩。"]'),
('d42a40a4-4632-4133-b034-51af62035e42','中秋無月三首  其二','范成大','宋','宋诗','song-poetry','','[]','撲地癡雲欲萬重，家家簾幙護房櫳。',32,'全唐诗/poet.song.138000.json','["撲地癡雲欲萬重，家家簾幙護房櫳。", "世間第一無情物，誰似中秋雨與風。"]'),
('e5c0f1bc-2d8b-4678-af56-cb98c8afe828','中秋無月三首  其三','范成大','宋','宋诗','song-poetry','','[]','一生露下風前客，兩歲愁邊病裏身。',32,'全唐诗/poet.song.138000.json','["一生露下風前客，兩歲愁邊病裏身。", "姑置陰晴圓缺事，藥寮燈火正相親。"]'),
('f16931b7-7d8e-473c-aac4-0fbb58fc9548','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其一','范成大','宋','宋诗','song-poetry','','[]','舊歲連新歲，凉牀又煖牀。',48,'全唐诗/poet.song.138000.json','["舊歲連新歲，凉牀又煖牀。", "山川屏裏畫，時刻篆中香。", "畏壘吾安土，支離飽太倉。", "若教身更健，鶴背入維揚。"]'),
('bab73e21-e9e0-4541-a4c2-58cf1d5707c0','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其二','范成大','宋','宋诗','song-poetry','','[]','認鹿紛紜夢，亡羊散亂心。',48,'全唐诗/poet.song.138000.json','["認鹿紛紜夢，亡羊散亂心。", "眵昏遮眼讀，愁苦撚髭吟。", "幸覺行迷遠，其如卧病深。", "通身都放下，何用覓砭鍼。"]'),
('dfd4190a-bbde-4211-8549-ba5f4a3e067c','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其三','范成大','宋','宋诗','song-poetry','','[]','日煖衣猶襲，宵長被有稜。',48,'全唐诗/poet.song.138000.json','["日煖衣猶襲，宵長被有稜。", "朝晡三楪飯，昏曉一釭燈。", "伴坐跧如几，扶行瘦比藤。", "生緣堪入畫，寂寞憩松僧。"]'),
('7035ccba-d39d-4e8c-af58-41d84a1f4fcc','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其四','范成大','宋','宋诗','song-poetry','','[]','繩倚扶枵骨，蒲團閣瘁膚。',48,'全唐诗/poet.song.138000.json','["繩倚扶枵骨，蒲團閣瘁膚。", "事疑償業債，形類窘囚拘。", "空劫真常體，浮生幻化軀。", "箇中元不二，無語對文殊。"]'),
('c39c509a-9483-459d-b60c-d1c1ed1a3c99','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其五','范成大','宋','宋诗','song-poetry','','[]','軟熟羞盤饌，芳辛實枕幃。',48,'全唐诗/poet.song.138000.json','["軟熟羞盤饌，芳辛實枕幃。", "候晴先晒席，占濕豫烘衣。", "易粟雞皮皺，難培鶴骨肥。", "頭顱雖若此，虛白自生輝。"]'),
('2468ec26-0b62-4b55-88de-eebdf3c44f26','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其六','范成大','宋','宋诗','song-poetry','','[]','數息憎晨凊，伸眉愜晚晴。',48,'全唐诗/poet.song.138000.json','["數息憎晨凊，伸眉愜晚晴。", "隙塵浮日影，窗穴嘯風聲。", "捫蝨天機動，驅蚊我相生。", "偶然成一笑，栩栩暫身輕。"]'),
('ee37c730-6341-4ba5-a1f7-2f57c64f287c','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其七','范成大','宋','宋诗','song-poetry','','[]','貴仕龜鑽筴，閒居馬脫鞿。',48,'全唐诗/poet.song.138000.json','["貴仕龜鑽筴，閒居馬脫鞿。", "冠塵昏舊製，带眼剩新圍。", "堆案書郵少，登門刺字稀。", "掩關灰木坐，休示季咸機。"]'),
('83032452-c35f-44a5-821d-8d71949e07bd','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其八','范成大','宋','宋诗','song-poetry','','[]','目眚浮珠珮，聲塵籟玉簫。',48,'全唐诗/poet.song.138000.json','["目眚浮珠珮，聲塵籟玉簫。", "秋懷潘鬢禿，午夢楚魂銷。", "注水瓶花醒，吹薪藥鼎潮。", "南柯何處是，斜日上廊腰。"]'),
('a62c6426-2f9c-4a91-bc47-098a4187dbac','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其九','范成大','宋','宋诗','song-poetry','','[]','靜裏秋先到，閒中晝自長。',48,'全唐诗/poet.song.138000.json','["靜裏秋先到，閒中晝自長。", "門闌疑泄柳，尸祝漫庚桑。", "腹已枵經笥，身猶試藥方。", "强名今日愈，勃窣負東牆。"]'),
('1655ced4-b48d-401d-be21-29ff4566c803','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其一○','范成大','宋','宋诗','song-poetry','','[]','汗漬筇枝赤，苔封屐齒青。',48,'全唐诗/poet.song.138000.json','["汗漬筇枝赤，苔封屐齒青。", "有醫延上坐，無客抗分庭。", "霽月鑽窗看，鳴琴側枕聽。", "莫嗔猿鶴怨，岫幌兩年扃。"]'),
('a40d60a8-cd7e-4e3f-89ff-4c759163ac83','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其一一','范成大','宋','宋诗','song-poetry','','[]','視絮勞群從，祗承愧闔家。',48,'全唐诗/poet.song.138000.json','["視絮勞群從，祗承愧闔家。", "乳泉供水遞，金液養丹芽。", "加釀厚如酪，旋舂香勝花。", "百端扶老憊，無物報投瓜。"]'),
('f01c1073-63a6-4bbc-afef-ca6bbe0f3f22','藻姪比課五言詩已有意趣老懷甚喜因吟病中十二首示之可率昆季賡和勝終日飽閒也  其一二','范成大','宋','宋诗','song-poetry','','[]','學業荒呻畢，歡悰隔笑鹽。',48,'全唐诗/poet.song.138000.json','["學業荒呻畢，歡悰隔笑鹽。", "入秋先複幕，過夏亦疎簾。", "門客嗔愁思，家人獻吉占。", "尤憐小兒女，時報鵲鳴簷。"]'),
('878c77bd-daf2-4591-8afd-e9ea7f162f14','贈臨江簡壽玉二首簡携王仲顯使君書來謁并示孔毅甫夢蟾圖今廟堂五府皆有題字  其一','范成大','宋','宋诗','song-poetry','','[]','蕭灘遠客扣田廬，貽我讀書樓上書。',32,'全唐诗/poet.song.138000.json','["蕭灘遠客扣田廬，貽我讀書樓上書。", "千里故情元共月，錯云多病故人疎。"]'),
('44b09ee8-0c56-4615-97c9-3092323e5d4a','贈臨江簡壽玉二首簡携王仲顯使君書來謁并示孔毅甫夢蟾圖今廟堂五府皆有題字  其二','范成大','宋','宋诗','song-poetry','','[]','卷中圖畫袖中珍，上有三階五朶雲。',32,'全唐诗/poet.song.138000.json','["卷中圖畫袖中珍，上有三階五朶雲。", "白日青天光範路，未饒蟾窟夢紛紜。"]'),
('47bef01f-6641-4883-bc36-a5c16b742c59','壽櫟前假山成移丹桂於馬城自嘲','范成大','宋','宋诗','song-poetry','','[]','堂前趣就小嶙峋，未許蹣跚杖屨親。',32,'全唐诗/poet.song.138000.json','["堂前趣就小嶙峋，未許蹣跚杖屨親。", "更遣移花三百里，世間真有大癡人。"]'),
('09c9273c-ca5b-4eda-a618-88e0984018c1','灼艾','范成大','宋','宋诗','song-poetry','','[]','血忌詳涓日，尻神謹避方。',48,'全唐诗/poet.song.138000.json','["血忌詳涓日，尻神謹避方。", "艾求真伏道，穴按古明堂。", "謝去群巫祝，勝如幾藥湯。", "起來成獨笑，一病攪千忙。"]'),
('142fb18d-7695-43d9-b6a0-77ba30fe2eb4','東宮壽詩','范成大','宋','宋诗','song-poetry','','[]','甲觀秋彌月，前星蚤麗天。',144,'全唐诗/poet.song.138000.json','["甲觀秋彌月，前星蚤麗天。", "君親重慶日，家國中興年。", "英武神機遠，溫文德宇全。", "摛章森典則，會道極高堅。", "儉寶躬安履，仁端性自然。", "淵沖澄有量，海潤浹無邊。", "五學臨函丈，三朝拱邃延。", "頌聲敷政久，喜色問安還。", "銅律諧初度，桑弧絕舊傳。", "菊催重九近，梅占小春先。", "戲綵猗蘭殿，宣杯玳瑁筵。", "青宮千億壽，長對兩宮前。"]'),
('c54e4c4b-b1cc-497d-9563-81de376b12ef','十月朝開爐偶書余病歸二年未能拜埽松楸曩常以此日侍先兄遊洞庭并寫悲感之懷','范成大','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','圃芋今年紫，籬楓昨日丹。',48,'全唐诗/poet.song.138000.json','["圃芋今年紫，籬楓昨日丹。", "開爐修故事，聽雨說新寒。", "橘社重遊阻，楸行再拜難。", "此時西望眼，衰涕不勝彈。"]'),
('37a4c835-8beb-49a2-bebd-dcba55799103','有懷龔養正','范成大','宋','宋诗','song-poetry','','[]','好在楚龔子，秋來情話稀。',48,'全唐诗/poet.song.138000.json','["好在楚龔子，秋來情話稀。", "昨承書素說，行侍板輿歸。", "煙水潮平棹，風霜歲晚衣。", "幾時真訪戴，莫待雪花霏。"]'),
('4eb1dcdd-f721-44a3-b32a-8626322d9165','白髭行','范成大','宋','宋诗','song-poetry','','[]','四十踰四髭始黄，手持漢節臨大荒。',160,'全唐诗/poet.song.138000.json','["四十踰四髭始黄，手持漢節臨大荒。", "輿疾歸來皮骨在，兩鬢尚作青絲光。", "俛仰行年四十九，萬里南馳復西走。", "斑斑頷下點吳霜，猶可芟夷誑賓友。", "屈指如今又十年，兩年憊卧秋風前。", "人生血氣能幾許，不待覽鏡知皤然。", "長安後輩輕前輩，百方染藥千金賣。", "煩撋包裹夜不眠，無奈露頭出光怪。", "病翁高卧門長扃，垂雪毿毿骨更清。", "兒童不作居士喚，喚作堂中老壽星。"]'),
('be1c8396-3c0b-4985-939f-41da6e14841c','但能之提刑相別十年自曲江遠寄二詩敘舊良厚次韻爲謝亦以首章奉懷略道湘南分携故事末篇自述年來衰病不復故吾也  其一','范成大','宋','宋诗','song-poetry','','[]','憶昔驂鸞識俊英，朱旛繡斧盡能名。',64,'全唐诗/poet.song.138000.json','["憶昔驂鸞識俊英，朱旛繡斧盡能名。", "書隨庾嶺一枝寄，句挾韶江九奏成。", "吳粵交馳清夜夢，參辰不隔故人情。", "何時重醉金槽曲，一洗陽關別恨平。"]'),
('0dbc7099-6be2-4200-8d22-ad71a211e016','但能之提刑相別十年自曲江遠寄二詩敘舊良厚次韻爲謝亦以首章奉懷略道湘南分携故事末篇自述年來衰病不復故吾也  其二','范成大','宋','宋诗','song-poetry','','[]','濩落枵虛似瓠壺，新添雪鬢與霜鬚。',64,'全唐诗/poet.song.138000.json','["濩落枵虛似瓠壺，新添雪鬢與霜鬚。", "也知病叟形容變，非是仙儒骨相癯。", "歲晚山林如自獻，年豐田野亦多娛。", "無端拙恙妨清樂，未許扁舟到五湖。"]'),
('83b7411f-5e62-4123-82e6-a6ea3f934430','復以蟾硯歸龔養正','范成大','宋','宋诗','song-poetry','','[]','夢裏何人歌式微，覺來石友在書幃。',64,'全唐诗/poet.song.138000.json','["夢裏何人歌式微，覺來石友在書幃。", "鄭環信美非吾寶，趙璧猶全任汝歸。", "渴水雙蟾窺海闊，出雲孤月照星稀。", "好將自草三千牘，莫與蚍蜉作釣磯。"]'),
('b9093b86-e9df-4289-b761-a1e4d9068d54','大雪書懷','范成大','宋','宋诗','song-poetry','','[]','天將奇賞發清歡，疇昔登臨插羽翰。',64,'全唐诗/poet.song.138000.json','["天將奇賞發清歡，疇昔登臨插羽翰。", "梅下尋詩騎馬滑，松梢索酒倚樓寒。", "閉門老子愁無頼，返棹歸來興已闌。", "聊掬玉塵添石鼎，自煎魚眼破龍團。"]'),
('5e2e1ab0-afb3-4527-865c-f685626671e2','雪中苦寒戲嘲二絕  其一','范成大','宋','宋诗','song-poetry','','[]','冥凌分職大間關，辛苦行冬强作難。',32,'全唐诗/poet.song.138000.json','["冥凌分職大間關，辛苦行冬强作難。", "費盡無邊風與雪，劣能供得一番寒。"]'),
('dc68e509-7eac-4e16-a04a-0c81647d8c7f','雪中苦寒戲嘲二絕  其二','范成大','宋','宋诗','song-poetry','','[]','茸氈帳下玉杯寬，香裏吹笙醉裏看。',32,'全唐诗/poet.song.138000.json','["茸氈帳下玉杯寬，香裏吹笙醉裏看。", "風雪過門無入處，却投窮巷覓袁安。"]'),
('b34851a8-32b3-4834-a139-27eba1f2a4c3','雪復大作六言四首  其一','范成大','宋','宋诗','song-poetry','','[]','奇寒擁被曉枕，噩夢披蓑晚江。',28,'全唐诗/poet.song.138000.json','["奇寒擁被曉枕，噩夢披蓑晚江。", "遥想漫天匝地，近聽穿幔鳴窗。"]'),
('5acd7f1a-8aaa-4bcc-a0b7-941b1c26fea1','雪復大作六言四首  其二','范成大','宋','宋诗','song-poetry','','[]','釀成送臘三白，功在迎年九秋。',28,'全唐诗/poet.song.138000.json','["釀成送臘三白，功在迎年九秋。", "樵指擔肩相賀，飯囊酒甕何憂。"]'),
('b6e433e8-826f-4195-a51e-3db0c2fb045a','雪復大作六言四首  其三','范成大','宋','宋诗','song-poetry','','[]','初報折篁搶地，旋聞壓柳堆橋。',28,'全唐诗/poet.song.138000.json','["初報折篁搶地，旋聞壓柳堆橋。", "寧教風過掀舞，可惜雨來半銷。"]'),
('2de41025-f5b6-44d7-9377-4f07ff230302','雪復大作六言四首  其四','范成大','宋','宋诗','song-poetry','','[]','伶俜凍雀蹲晚，噤滲疎梅鎖春。',28,'全唐诗/poet.song.138000.json','["伶俜凍雀蹲晚，噤滲疎梅鎖春。", "有客典衣沽酒，何人增價賣薪。"]'),
('bed8a48d-1f10-47e7-afe7-cf0b587a1f17','立春','范成大','宋','宋诗','song-poetry','','[]','綵勝金旛夢裏，茶槽藥杵聲中。',28,'全唐诗/poet.song.138000.json','["綵勝金旛夢裏，茶槽藥杵聲中。", "索莫兩年春事，小窗卧聽東風。"]'),
('1e0b80dd-3136-43d6-ad31-714a1439a715','題徐熙風牡丹二首 紫花','范成大','宋','宋诗','song-poetry','','[]','蕊珠仙馭曉驂鸞，道服朝元露未乾。',32,'全唐诗/poet.song.138000.json','["蕊珠仙馭曉驂鸞，道服朝元露未乾。", "天半剛風如激箭，綠綃飄蕩紫綃寒。"]'),
('ff82fe02-1cf5-4f31-b008-c5fd8bd08a70','題徐熙風牡丹二首 白花','范成大','宋','宋诗','song-poetry','','[]','寒入仙裙粟玉肌，舞餘全不耐風吹。',32,'全唐诗/poet.song.138000.json','["寒入仙裙粟玉肌，舞餘全不耐風吹。", "從教旅拒春無力，細看腰支嫋嫋時。"]'),
('6f30e27b-cab8-4740-aa14-01c7af2122a6','題黄居寀雀竹圖二首  其一','范成大','宋','宋诗','song-poetry','','[]','群雀歲寒保聚，兩鶉日晏忘歸。',28,'全唐诗/poet.song.138000.json','["群雀歲寒保聚，兩鶉日晏忘歸。", "草間豈無餘粒，刮地風號雪飛。"]'),
('36821e61-c14b-4ce2-98b3-cfe673d7be67','題黄居寀雀竹圖二首  其二','范成大','宋','宋诗','song-poetry','','[]','蔓花露下凝碧，叢竹秋來老蒼。',28,'全唐诗/poet.song.138000.json','["蔓花露下凝碧，叢竹秋來老蒼。", "噪雀群爭何事，么禽自囀清篁。"]'),
('fb5daae4-2a7f-4b4b-8ce0-ce85b70911ea','題張晞顔兩花圖二首 繁杏','范成大','宋','宋诗','song-poetry','','[]','紅粉團枝一萬重，當年獨自費東風。',32,'全唐诗/poet.song.138000.json','["紅粉團枝一萬重，當年獨自費東風。", "若爲報答春無頼，付與笙歌鼎沸中。"]'),
('1bf11130-8fd0-4117-ac1f-5f97714fb0c2','題張晞顔兩花圖二首 玉梨','范成大','宋','宋诗','song-poetry','','[]','雪薄冰輕不耐春，雨中愁緒月中真。',32,'全唐诗/poet.song.138000.json','["雪薄冰輕不耐春，雨中愁緒月中真。", "莫教夢作雲飛去，留伴昭陽第一人。"]'),
('9a3b4171-b2b8-4e3d-9bb5-d0abfebfe69e','題范道士二牛圖','范成大','宋','宋诗','song-poetry','','[]','西疇滌場浄無塵，原頭遠牧秋草春。',64,'全唐诗/poet.song.138000.json','["西疇滌場浄無塵，原頭遠牧秋草春。", "一牛疾行離其群，一牛返顧如怒嗔。", "目光炯炯獰而馴，點綴毫末俱逼真。", "不顛不狂筆有神，妙哉吾宗散仙人。"]'),
('f6ee4798-9817-4d91-aec1-dd3a7bcf7c77','小峨眉','范成大','宋','宋诗','song-poetry','','["\u592a\u6e56"]','三峨參橫大峨高，奔崖側勢倚半霄。',352,'全唐诗/poet.song.138000.json','["三峨參橫大峨高，奔崖側勢倚半霄。", "龍跧虎卧起且伏，旁睨沫水沱江朝。", "禹從岷嶓過其下，奠山著籍稱雄豪。", "告成歸來兩階舞，泗濱錫貢備九韶。", "覽觀此石三歎息，髣髴蜀鎮俱岧嶢。", "惜哉擊拊墮簨虡，輦送淮海還山椒。", "降商訖周謹呵護，磬氏無敢加鎸彫。", "劉項蝸爭鬨靈壁，血漂川谷流腥臊。", "水官恐此被染涴，氈包席裹吳中逃。", "市門大隠閲千祀，苔衣塵網薶孤標。", "尤物顯晦定有數，昨者惠顧不待招。", "我昔西遊踏禹迹，暑宿光相披重貂。", "十年境落卧榼夢，摩挲壁畫雙鬢凋。", "天憐愛山欲成癖，特設奇供慰寂寥。", "恍然坐我寶巖上，疑有太古雪未消。", "嵌根襞積巧入妙，峰頂箕踞貴不驕。", "爐煙雲浮布銀界，隙日虹貫凝金橋。", "是時歲杪卧衰疾，健起放杖驚兒曹。", "龍鍾繞圍喜折屐，龜手拂拭寒侵袍。", "太湖未暇商甲乙，羅浮天竺均鴻毛。", "小峨之名神所畀，永與野老歸漁樵。", "作詩賀我得石友，且以併賀茲丘遭。"]'),
('7a80dca5-3565-461a-9138-977702ec1c32','煙江疊嶂','范成大','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖嵌根藏洞宮，槎牙石生奫淪中。',128,'全唐诗/poet.song.138000.json','["太湖嵌根藏洞宮，槎牙石生奫淪中。", "波濤投隙漱且囓，歲久缺罅深重重。", "水空發聲夜鏜鎝，中有晴江煙嶂疊。", "誰歟斷取來何時，山客自言藏奕葉。", "江上愁心惟畫圖，蘇仙作詩畫不如。", "當年此石若並世，雪浪仇池何足書。", "我無俊語對巨麗，欲定等差誰與議。", "直須具眼老香山，來爲平章作新記。"]'),
('aeaaf66b-d872-47c9-8a3a-0e6038989031','天柱峰','范成大','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山紫蓋連延處，一峰巉絕擎玉宇。',128,'全唐诗/poet.song.138000.json','["衡山紫蓋連延處，一峰巉絕擎玉宇。", "漢家憚遠不能到，寓祭灊山作天柱。", "我今卧遊長揜關，却寓此石充灊山。", "形摹三尺氣萬仞，世間培塿何由攀。", "南州山骨朶清淑，乳孽砂牀未超俗。", "神奇都賦小崢嶸，雷雨飛來伴幽獨。", "哦詩月明清夜闌，坐看高影橫屋山。", "摩霄拂雲政如此，吾言實夸誰敢刪。"]'),
('d22e4aab-7b01-4138-859d-7f8c5ccd1a95','甲辰除夜吟','范成大','宋','宋诗','song-poetry','','[]','一年三百六十日，日日三椽卧衰疾。',160,'全唐诗/poet.song.138000.json','["一年三百六十日，日日三椽卧衰疾。", "旁人揶揄還歎咨，問我如何度四時。", "我言平生老行李，蓐食趁程中夜起。", "當時想像閉門閒，弱水迢迢三萬里。", "如今因病得疎慵，脚底關山如夢中。", "重簾複幕白晝靜，戶外車馬從西東。", "若問四時何以度，念定更無新與故。", "瓶花開落紀春冬，窗紙昏明認朝暮。", "行年六十是明朝，不暇自憐聊自嘲。", "婪尾三杯餳一楪，從今身健齒牙牢。"]'),
('7f414679-a17d-4c24-8ae7-ba18db336271','次韻龔養正送水仙花','范成大','宋','宋诗','song-poetry','','[]','色界香塵付八還，正觀不起況邪觀。',32,'全唐诗/poet.song.138000.json','["色界香塵付八還，正觀不起況邪觀。", "花前猶有詩情在，還作凌波步月看。"]'),
('e5985117-2519-41eb-8d35-71953a86d057','元日','范成大','宋','宋诗','song-poetry','','[]','屋角崢嶸斗柄移，案頭蕭索燭花垂。',64,'全唐诗/poet.song.138000.json','["屋角崢嶸斗柄移，案頭蕭索燭花垂。", "與時消息評新藥，若節春秋憶舊詩。", "饑飯困眠全體懶，風餐露宿半生癡。", "尊前現在休嫌老，最後屠蘇把一巵。"]'),
('2c85988d-46cb-4244-9d80-a547ef73f945','正月六日風雪大作  其一','范成大','宋','宋诗','song-poetry','','[]','滕六無端巽二癡，翻天作惡破春遲。',32,'全唐诗/poet.song.138000.json','["滕六無端巽二癡，翻天作惡破春遲。", "邀梅勒柳何功業，誰與停杯一問之。"]'),
('c5b5c32e-9dc5-4ded-b522-b4510868a3cb','正月六日風雪大作  其二','范成大','宋','宋诗','song-poetry','','[]','奇寒何事入芳辰，不管燈枝欲試新。',32,'全唐诗/poet.song.138000.json','["奇寒何事入芳辰，不管燈枝欲試新。", "即日反風吹盡雪，東君已費一分春。"]'),
('7a96c2b6-6030-4b65-a987-1efd05e1b70b','元夕四首  其一','范成大','宋','宋诗','song-poetry','','[]','粉痕紅點萬花攢，玉氣珠光寶月團。',32,'全唐诗/poet.song.138000.json','["粉痕紅點萬花攢，玉氣珠光寶月團。", "簾箔通明香似霧，東君無處著春寒。"]'),
('10d920dc-bdc6-429a-9986-f24904cc3261','元夕四首  其二','范成大','宋','宋诗','song-poetry','','[]','不夜城中陸地蓮，小梅初破月初圓。',32,'全唐诗/poet.song.138000.json','["不夜城中陸地蓮，小梅初破月初圓。", "新年第一佳時節，誰肯如翁閉戶眠。"]'),
('544cc342-8a44-42f2-b39b-4abd6067f074','元夕四首  其三','范成大','宋','宋诗','song-poetry','','[]','藥爐湯鼎煮孤燈，禪版蒲團老病僧。',32,'全唐诗/poet.song.138000.json','["藥爐湯鼎煮孤燈，禪版蒲團老病僧。", "兒女强修元夕供，玉蛾先避雪鬅鬙。"]'),
('9393305d-a954-4d50-b977-f95f6227ab50','元夕四首  其四','范成大','宋','宋诗','song-poetry','','[]','落梅穠李趁時新，枯木崖邊一任春。',32,'全唐诗/poet.song.138000.json','["落梅穠李趁時新，枯木崖邊一任春。", "尚愛鄉音醒病耳，隔牆時有賣餳人。"]'),
('d9041451-6675-4cf2-886e-688a9556f11c','去年多雪苦寒梅花遂晚元夕猶未盛開','范成大','宋','宋诗','song-poetry','','[]','隔年寒力凍芳塵，勒住東風寂寞濱。',64,'全唐诗/poet.song.138000.json','["隔年寒力凍芳塵，勒住東風寂寞濱。", "只管苦吟三尺雪，那知遲把一枝春。", "燈烘畫閣香猶冷，湯煖銅瓶玉尚皴。", "花定有情堪索笑，自憐無術喚真真。"]'),
('b5e08f2a-df49-4614-ba3f-aed194b4d54f','寄題筠州錢有文明府新昌小道院  其一','范成大','宋','宋诗','song-poetry','','[]','忠厚平生心學，敏明隨處民功。',28,'全唐诗/poet.song.138000.json','["忠厚平生心學，敏明隨處民功。", "江左幕中荒政，江西縣裏仁風。"]'),
('a14de08b-7919-4494-916d-009a956f29d6','寄題筠州錢有文明府新昌小道院  其二','范成大','宋','宋诗','song-poetry','','[]','勿云私淑小邑，可以匹休大邦。',28,'全唐诗/poet.song.138000.json','["勿云私淑小邑，可以匹休大邦。", "健筆誰能後賦，向來江夏無雙。"]'),
('19e8a529-0c38-416d-bc62-ec45e1781ce6','題徐熙杏花','范成大','宋','宋诗','song-poetry','','[]','老枝當歲寒，芳蘤春澹泞。',24,'全唐诗/poet.song.138000.json','["老枝當歲寒，芳蘤春澹泞。", "霧綃輕欲無，嬌紅恐飛去。"]'),
('df3c49ea-d17b-4a2d-a238-e518020d227a','題趙昌木瓜花','范成大','宋','宋诗','song-poetry','','[]','秋風魏瓠實，春雨燕脂花。',24,'全唐诗/poet.song.138000.json','["秋風魏瓠實，春雨燕脂花。", "綵筆不可寫，滴露勻朝霞。"]'),
('de34a3ba-4abf-456f-a99e-1610e2fe7b6c','題易元吉獐猿兩圖二首  其一','范成大','宋','宋诗','song-poetry','','[]','擇食麕相喚，無人意不驚。',24,'全唐诗/poet.song.138000.json','["擇食麕相喚，無人意不驚。", "猿啼風動葉，機熟兩忘情。"]'),
('8f289b7a-7139-4401-9d40-8374dedc6165','題易元吉獐猿兩圖二首  其二','范成大','宋','宋诗','song-poetry','','[]','烏逐山公噪，驚麕仰望疑。',24,'全唐诗/poet.song.138000.json','["烏逐山公噪，驚麕仰望疑。", "春林無一事，獝狘自生悲。"]'),
('ff7e3465-18b6-491c-adfa-f8c220d045ae','題張希賢紙本花四首 牡丹','范成大','宋','宋诗','song-poetry','','[]','洛花肉紅姿，蜀筆丹砂染。',24,'全唐诗/poet.song.138000.json','["洛花肉紅姿，蜀筆丹砂染。", "生綃多俗格，紙本有真艷。"]'),
('92302fb0-bbc3-455f-8cb9-b66ccf0d2874','題張希賢紙本花四首 常春','范成大','宋','宋诗','song-poetry','','[]','染根得靈藥，無時不春風。',24,'全唐诗/poet.song.138000.json','["染根得靈藥，無時不春風。", "倚闌與挂壁，相伴歲寒中。"]'),
('ef2e32c1-1e07-44dc-ad95-044dd7903015','題張希賢紙本花四首 紅梅','范成大','宋','宋诗','song-poetry','','[]','酒力欺朝寒，潮紅上粧面。',24,'全唐诗/poet.song.138000.json','["酒力欺朝寒，潮紅上粧面。", "桃李漫同時，輸了春風半。"]'),
('cf5d2df0-2695-4cc4-883d-cf4125c37548','題張希賢紙本花四首 雞冠','范成大','宋','宋诗','song-poetry','','[]','號名極形似，摹寫與真逼。',24,'全唐诗/poet.song.138000.json','["號名極形似，摹寫與真逼。", "聊以畫滑稽，慰我秋園寂。"]'),
('49a9e5a4-d8c4-415a-b516-d8887ddfb581','喜沈叔晦至','范成大','宋','宋诗','song-poetry','','[]','澹若論交味，嚶其求友聲。',48,'全唐诗/poet.song.138000.json','["澹若論交味，嚶其求友聲。", "江湖幾魚沫，風雨一雞鳴。", "舊事休重說，新詩莫細評。", "煩將憶勤夢，歸對海山橫。"]'),
('695b31f6-544b-48f2-9ba1-e0371a28b11d','驚蟄家人子輩爲易疏簾','范成大','宋','宋诗','song-poetry','','[]','二分春色到窮閻，兒女祈翁出滯淹。',64,'全唐诗/poet.song.138000.json','["二分春色到窮閻，兒女祈翁出滯淹。", "幽蟄夜驚雷奮地，小窗朝爽日篩簾。", "惠風全解墨池凍，清晝賸繙雲笈籤。", "親友莫嗔情話少，向來屏息似龜蟾。"]'),
('bf87d584-dad0-40f5-8042-0c4e3907c252','信筆','范成大','宋','宋诗','song-poetry','','[]','天地同浮水上萍，羲娥迭耀案頭螢。',64,'全唐诗/poet.song.138000.json','["天地同浮水上萍，羲娥迭耀案頭螢。", "山中名器兩芒屩，花下友朋雙玉瓶。", "童子昔曾誇了了，主翁今但諾醒醒。", "歸田贏得多無事，輸與諸公汗簡青。"]'),
('943bbe08-9b17-4f03-9253-b796e5904dd2','請息齋書事三首  其一','范成大','宋','宋诗','song-poetry','','[]','覆雨翻雲轉手成，紛紛輕薄可憐生。',64,'全唐诗/poet.song.138000.json','["覆雨翻雲轉手成，紛紛輕薄可憐生。", "天無寒暑無時令，人不炎凉不世情。", "栩栩算來俱蝶夢，喈喈能有幾雞鳴。", "冰山側畔紅塵漲，不隔瑶臺月露清。"]'),
('12547685-2f74-4b64-8b39-1f9a4aa27c26','請息齋書事三首  其二','范成大','宋','宋诗','song-poetry','','[]','刻木牽絲罷戲場，祭餘雨後兩相忘。',64,'全唐诗/poet.song.138000.json','["刻木牽絲罷戲場，祭餘雨後兩相忘。", "門雖有雀尚廷尉，食已無魚休孟嘗。", "蝨裏趨時真是賊，虎中宣力任爲倀。", "籬東舍北誰情話，雞語鷗盟意却長。"]'),
('5f8a2eb3-df17-400c-8f42-7215f0ce53a7','請息齋書事三首  其三','范成大','宋','宋诗','song-poetry','','[]','聚蚋醯邊閙似雷，乞兒爭背向寒灰。',64,'全唐诗/poet.song.138000.json','["聚蚋醯邊閙似雷，乞兒爭背向寒灰。", "長平失勢見何晚，栗里息交歸去來。", "休問江湖魚有沫，但蘄雲水鶴無媒。", "巖扉岫幌牢扃鑰，不是漁樵不與開。"]'),
('c54cbb56-ec52-494c-ba19-9fdeb414281a','送文季高倅興元','范成大','宋','宋诗','song-poetry','','[]','素衣京洛悵成緇，青鬢江吳喜未絲。',64,'全唐诗/poet.song.138000.json','["素衣京洛悵成緇，青鬢江吳喜未絲。", "燭暗不眠談舊事，酒闌作惡問行期。", "琴書情話須親戚，風雨殘春更別離。", "屈指歸來重一笑，掃除門巷著旌麾。"]'),
('0d51aa98-1247-47fa-9897-9e656b14e330','書懷二絕再送文季高兼呈新帥閻才元侍郎  其一','范成大','宋','宋诗','song-poetry','','[]','劍關雲棧守非難，函谷泥封久未刊。',32,'全唐诗/poet.song.138000.json','["劍關雲棧守非難，函谷泥封久未刊。", "今日漢中誰國士，莫教春草上齋壇。"]'),
('b5f3878e-592f-4cc0-9855-3c489a3212ff','書懷二絕再送文季高兼呈新帥閻才元侍郎  其二','范成大','宋','宋诗','song-poetry','','[]','西出陽關有舊知，薰風淥水泛蓮時。',32,'全唐诗/poet.song.138000.json','["西出陽關有舊知，薰風淥水泛蓮時。", "煩君傳語詩書帥，更寄臺城別後詞。"]'),
('01af0440-be58-49ed-866f-9e3500056e86','寄題石湖海棠二首  其一','范成大','宋','宋诗','song-poetry','','[]','手開芳徑越城頭，紅錦屠蘇結綺樓。',32,'全唐诗/poet.song.138000.json','["手開芳徑越城頭，紅錦屠蘇結綺樓。", "不把萬枝銀燭照，淡雲微月替人愁。"]'),
('da8a519e-b16a-469f-8966-1bf7a01a65a5','寄題石湖海棠二首  其二','范成大','宋','宋诗','song-poetry','','[]','老懶居家似出家，園林春色雨沾沙。',32,'全唐诗/poet.song.138000.json','["老懶居家似出家，園林春色雨沾沙。", "海棠尚自無心看，天女何須更散花。"]'),
('ec285d6b-7f91-4364-aba7-446af5f08129','家人子輩往石湖檢校暮歸','范成大','宋','宋诗','song-poetry','','[]','南浦回春棹，東城掩暮扉。',48,'全唐诗/poet.song.138000.json','["南浦回春棹，東城掩暮扉。", "兒修雞柵了，女挈菜籃歸。", "風力雖欺酒，花香尚染衣。", "衰翁牢守舍，腸斷釣魚磯。"]'),
('fc44322b-148b-4d64-88d0-fe935008c74e','枕上聞蒲餠焦','范成大','宋','宋诗','song-poetry','','[]','曉寒燕雀噤春陰，珍重清簧度好音。',32,'全唐诗/poet.song.138000.json','["曉寒燕雀噤春陰，珍重清簧度好音。", "窗色熹微欹枕聽，夢成舟檥竹溪深。"]'),
('4dd16264-bd78-462b-9330-c43d160a1f3e','石湖芍藥盛開向北使歸過維揚時買根栽此因記舊事二首  其一','范成大','宋','宋诗','song-poetry','','[]','竹西歌吹荻花秋，遺老垂洟送遠遊。',32,'全唐诗/poet.song.138000.json','["竹西歌吹荻花秋，遺老垂洟送遠遊。", "羌笛夜闌吹出塞，當年如此夢揚州。"]'),
('ce453700-00ee-41f0-9f66-a4de62f72eea','石湖芍藥盛開向北使歸過維揚時買根栽此因記舊事二首  其二','范成大','宋','宋诗','song-poetry','','[]','萬里歸程許過家，移將二十四橋花。',32,'全唐诗/poet.song.138000.json','["萬里歸程許過家，移將二十四橋花。", "石湖從此添春色，莫把蒲萄苜蓿誇。"]'),
('afd71f31-ca39-4a0c-b43d-e1aded01a140','次韻龔養正中秋無月三首  其一','范成大','宋','宋诗','song-poetry','','[]','詞客幕天清露下，老翁卧病破窗中。',32,'全唐诗/poet.song.138000.json','["詞客幕天清露下，老翁卧病破窗中。", "高吟大醉輸公等，不見嫦娥與我同。"]'),
('39057024-56db-4329-8db5-ee900c1e598e','次韻龔養正中秋無月三首  其二','范成大','宋','宋诗','song-poetry','','[]','去年怪雨無端甚，今歲癡雲亦復然。',32,'全唐诗/poet.song.138000.json','["去年怪雨無端甚，今歲癡雲亦復然。", "減却新詩酸却酒，乘除添得一更眠。"]'),
('43d25516-96d8-4eb5-a615-89f3fcd4eb5e','次韻龔養正中秋無月三首  其三','范成大','宋','宋诗','song-poetry','','[]','丙夜清光些子見，兒童驚喜强雄夸。',32,'全唐诗/poet.song.138000.json','["丙夜清光些子見，兒童驚喜强雄夸。", "闌珊高興應無幾，恰似春殘看落花。"]'),
('57ea9eae-b277-404d-99a4-ef36ac6109c4','殊不惡齋秋晚閒吟五絕  其一','范成大','宋','宋诗','song-poetry','','[]','好風入簾圖畫響，斜照穿隙網絲明。',32,'全唐诗/poet.song.138000.json','["好風入簾圖畫響，斜照穿隙網絲明。", "檐間雙雀有時鬭，壁下一蛩終日鳴。"]'),
('fbaa506f-8408-46cc-bccb-6251dd7c2343','殊不惡齋秋晚閒吟五絕  其二','范成大','宋','宋诗','song-poetry','','[]','旁若無人鼠飲硯，麾之不去蠅登盤。',32,'全唐诗/poet.song.138000.json','["旁若無人鼠飲硯，麾之不去蠅登盤。", "天凉睡起枕痕煖，日晚慵來香字寒。"]'),
('b26cb4bb-879e-4ebf-97a2-25b0aeddd4d2','殊不惡齋秋晚閒吟五絕  其三','范成大','宋','宋诗','song-poetry','','[]','就食遷居蟻墳壤，隨風作舍蛛裊絲。',32,'全唐诗/poet.song.138000.json','["就食遷居蟻墳壤，隨風作舍蛛裊絲。", "百年何處用三窟，萬事信緣安一枝。"]'),
('47dba799-6849-43e0-9ae2-32f0f0343fef','殊不惡齋秋晚閒吟五絕  其四','范成大','宋','宋诗','song-poetry','','[]','市聲洶洶鼓催陣，日影駸駸潮漲痕。',32,'全唐诗/poet.song.138000.json','["市聲洶洶鼓催陣，日影駸駸潮漲痕。", "消磨意氣默數息，把玩光陰牢閉門。"]'),
('21fcd02f-2969-48d7-bf5c-e7dc7584c94c','殊不惡齋秋晚閒吟五絕  其五','范成大','宋','宋诗','song-poetry','','[]','中秋昨已等閒過，重九今還如夢來。',32,'全唐诗/poet.song.138000.json','["中秋昨已等閒過，重九今還如夢來。", "霜鬢數莖羞墮幘，黄花三度笑空杯。"]'),
('95a437c7-65ee-4a2d-ba02-aadbd039b6f7','老陳道人自云夢被召作地上主者又常受一貴家供祝之曰他日必來吾家作兒戲贈小頌','范成大','宋','宋诗','song-poetry','','[]','野人何苦赴官差，符使追呼撓道懷。',32,'全唐诗/poet.song.138000.json','["野人何苦赴官差，符使追呼撓道懷。", "幸有于門香積供，不如隨喜去羅齋。"]'),
('88e39cb5-d3d0-4085-99fb-3e6717cd7dcb','題張戡蕃馬射獵圖','范成大','宋','宋诗','song-poetry','','[]','陰山磧中射生虜，馬逐箭飛如脫兔。',64,'全唐诗/poet.song.138000.json','["陰山磧中射生虜，馬逐箭飛如脫兔。", "割鮮大嚼飽何求，荐食中原天震怒。", "太乙靈旗方北指，掣轡逃歸莫南顧。", "猖狂若到殺胡林，郎主猶羓何況汝。"]'),
('60ab81ab-ce2d-43f3-91f2-1837cafad8ae','題趙昌四季花圖 海棠梨花','范成大','宋','宋诗','song-poetry','','[]','醉紅睡未熟，淚玉春带雨。',24,'全唐诗/poet.song.138000.json','["醉紅睡未熟，淚玉春带雨。", "阿環不可招，空寄凭肩語。"]'),
('dac5e08b-201b-4ccc-8a2d-5c3d164cb74f','題趙昌四季花圖 葵花萱草','范成大','宋','宋诗','song-poetry','','[]','衛足保明哲，忘憂助歡娛。',24,'全唐诗/poet.song.138000.json','["衛足保明哲，忘憂助歡娛。", "欣欣夏日永，媚我幽人廬。"]'),
('02d80276-3972-48ed-9242-47320d292004','題趙昌四季花圖 拒霜旱蓮','范成大','宋','宋诗','song-poetry','','[]','霜天木芙蓉，陸地旱蓮草。',24,'全唐诗/poet.song.138000.json','["霜天木芙蓉，陸地旱蓮草。", "水花雲錦盡，不見秋風好。"]'),
('31e9502f-9fcb-4827-a6d2-a5a3635aa51c','題趙昌四季花圖 梅花山茶','范成大','宋','宋诗','song-poetry','','[]','月淡玉逾瘦，雪深紅欲燃。',24,'全唐诗/poet.song.138000.json','["月淡玉逾瘦，雪深紅欲燃。", "同時不同調，聊用慰衰年。"]'),
('5235276c-c510-4fd7-90d7-d6abce16f4ff','乙巳十月朔開爐三首  其一','范成大','宋','宋诗','song-poetry','','[]','石湖今日開爐，紙窗銀白新糊。',28,'全唐诗/poet.song.138000.json','["石湖今日開爐，紙窗銀白新糊。", "童子燒紅榾柮，老翁睡煖氍毹。"]'),
('b332b25f-8e85-4cac-87fb-e44ba46a9f10','乙巳十月朔開爐三首  其二','范成大','宋','宋诗','song-poetry','','[]','石湖今日開爐，兩壁仍安畫圖。',28,'全唐诗/poet.song.138000.json','["石湖今日開爐，兩壁仍安畫圖。", "萬事篆煙曲几，百年毳衲團蒲。"]'),
('5838bb47-05a8-47ca-82d3-3fa2ea1eda7b','乙巳十月朔開爐三首  其三','范成大','宋','宋诗','song-poetry','','[]','石湖今日開爐，俗家恰似精廬。',28,'全唐诗/poet.song.138000.json','["石湖今日開爐，俗家恰似精廬。", "抆涕雖無情緒，吟詩却有工夫。"]'),
('efde5a5f-d54b-4d9b-946d-ddb03caab0cd','有歎二首  其一','范成大','宋','宋诗','song-poetry','','[]','春秋蘭菊殊調，南北馬牛異方。',28,'全唐诗/poet.song.138000.json','["春秋蘭菊殊調，南北馬牛異方。", "心醉井蛙海若，眼空鵬海鳩枋。"]'),
('53a4dd34-86c9-455e-8e60-36149455c0c0','有歎二首  其二','范成大','宋','宋诗','song-poetry','','[]','貧富交情乃見，炎凉歲序方成。',28,'全唐诗/poet.song.138000.json','["貧富交情乃見，炎凉歲序方成。", "越秦本異肥瘠，魯衛何曾弟兄。"]'),
('6664517a-d524-4f69-9302-b48d95152234','留簡伯俊','范成大','宋','宋诗','song-poetry','','[]','我昔賦遠遊，萬里無親朋。',168,'全唐诗/poet.song.138000.json','["我昔賦遠遊，萬里無親朋。", "惟君同懷抱，相從共茵憑。", "踰嶺穿瘴茅，捫參倚枯藤。", "隨行一瓶鉢，澹如雲水僧。", "火馳炎熱場，見此玉壺冰。", "東歸常愧君，無力相引繩。", "長材屈小邑，果以循吏稱。", "豈不有薦墨，翩然支郡丞。", "五溪在何許，水駛山崚嶒。", "漫仕不擇地，摶扶笑鯤鵬。", "獨有故意長，問疾訪姜肱。", "亹亹談昨夢，一一記吾曾。", "中年畏離別，況我雪鬅鬙。", "此意君自解，少留對青燈。"]'),
('749ea680-2de1-4dc1-8060-65e7e611c6ad','枕上有感','范成大','宋','宋诗','song-poetry','','[]','窗明似月曉光新，被煖如薰睡息勻。',32,'全唐诗/poet.song.138000.json','["窗明似月曉光新，被煖如薰睡息勻。", "衝雨販夫牆外過，故應嗤我是何人。"]'),
('e18826fd-6a57-4010-812c-91cc4c1b8463','夜坐有感','范成大','宋','宋诗','song-poetry','','[]','靜夜家家閉戶眠，滿城風雨驟寒天。',32,'全唐诗/poet.song.138000.json','["靜夜家家閉戶眠，滿城風雨驟寒天。", "號呼賣卜誰家子，想欠明朝糴米錢。"]'),
('576a54be-2f7f-4818-bebf-75650f175b3e','十月二十六日三偈  其一','范成大','宋','宋诗','song-poetry','','[]','聲聞與色塵，普以妙香薰。',24,'全唐诗/poet.song.138000.json','["聲聞與色塵，普以妙香薰。", "昔汝來迷我，今吾却戲君。"]'),
('e1b26165-7656-48d3-98c5-429f0bfc4728','十月二十六日三偈  其二','范成大','宋','宋诗','song-poetry','','[]','有箇安心法，無時不可行。',24,'全唐诗/poet.song.138000.json','["有箇安心法，無時不可行。", "只將今日事，隨分了今生。"]'),
('70f7ebce-9085-45ea-af09-a069e6c1a8f8','十月二十六日三偈  其三','范成大','宋','宋诗','song-poetry','','[]','窗外塵塵事，窗中夢夢身。',24,'全唐诗/poet.song.138000.json','["窗外塵塵事，窗中夢夢身。", "既知身是夢，一任事如塵。"]'),
('8187451d-27bc-4948-bec9-e16ef13002f3','吳歈一首送丘宗卿自平江移會稽','范成大','宋','宋诗','song-poetry','','[]','吳兒與君緣不薄，再騎竹馬迎南郭。',96,'全唐诗/poet.song.138000.json','["吳兒與君緣不薄，再騎竹馬迎南郭。", "吳兒與君緣復淺，坐席纔溫旗脚轉。", "東人賦重越吟悲，趣了茲段隨朝雞。", "胸奇百鍊當活國，君豈獨私吳與越。", "鶴鳴樟橋猿夜啼，匈奴未滅家何爲。", "功成他年歸結屋，好在山花休斬竹。"]'),
('c1f45d90-5962-47f3-a527-f4c87d3e631c','贈壽老','范成大','宋','宋诗','song-poetry','','[]','農圃規模昔共論，雲奎卜築又逢君。',32,'全唐诗/poet.song.138000.json','["農圃規模昔共論，雲奎卜築又逢君。", "眉菴壽老長隨喜，好箇拋梁伏願文。"]'),
('28ecc43c-2329-435f-bfc8-fa9a2de10480','再贈壽老','范成大','宋','宋诗','song-poetry','','[]','澹齋寂莫澹菴空，玉柱金庭一夢中。',32,'全唐诗/poet.song.138000.json','["澹齋寂莫澹菴空，玉柱金庭一夢中。", "我病君衰猶見在，莫嫌俱作白頭翁。"]'),
('c949045b-d54f-4172-b6f3-0732b89fd618','雪中聞牆外鬻魚菜者求售之聲甚苦有感三絕  其一','范成大','宋','宋诗','song-poetry','','[]','飯籮驅出敢偷閒，雪脛冰鬚慣忍寒。',32,'全唐诗/poet.song.138000.json','["飯籮驅出敢偷閒，雪脛冰鬚慣忍寒。", "豈是不能扃戶坐，忍寒猶可忍饑難。"]'),
('c1ebca70-0e42-4fd8-b17e-769d506baef0','雪中聞牆外鬻魚菜者求售之聲甚苦有感三絕  其二','范成大','宋','宋诗','song-poetry','','[]','憂渴焦山業海深，貪渠刀蜜坐成禽。',32,'全唐诗/poet.song.138000.json','["憂渴焦山業海深，貪渠刀蜜坐成禽。", "一身冒雪渾家煖，汝不能詩替汝吟。"]'),
('8f047339-4377-4a8f-a120-6a7c5963c3d3','雪中聞牆外鬻魚菜者求售之聲甚苦有感三絕  其三','范成大','宋','宋诗','song-poetry','','[]','啼號升斗抵千金，凍雀饑鴉共一音。',32,'全唐诗/poet.song.138000.json','["啼號升斗抵千金，凍雀饑鴉共一音。", "勞汝以生令至此，悠悠大塊亦何心。"]'),
('72389e0e-9da9-4a49-a546-2b84d573b54e','詠河市歌者','范成大','宋','宋诗','song-poetry','','[]','豈是從容唱渭城，箇中當有不平鳴。',32,'全唐诗/poet.song.138000.json','["豈是從容唱渭城，箇中當有不平鳴。", "可憐日晏忍饑面，强作春深求友聲。"]'),
('4127828d-7733-4aa8-bc86-1aad6ca1aeb5','偶箴','范成大','宋','宋诗','song-poetry','','[]','情知萬法本來空，猶復將心奉八風。',32,'全唐诗/poet.song.138000.json','["情知萬法本來空，猶復將心奉八風。", "逆順境來欣戚變，咄哉誰是主人翁。"]'),
('9de3aeb8-d9d0-410a-b08e-ef2f20c12432','丙午新正書懷十首  其一','范成大','宋','宋诗','song-poetry','','[]','不用桃符貼畫雞，身心安處是天倪。',64,'全唐诗/poet.song.138000.json','["不用桃符貼畫雞，身心安處是天倪。", "行年六十舊曆日，汗脚尺三新杖藜。", "祝我賸周花甲子，謝人深勸玉東西。", "春風若借筋骸便，先渡南村學灌畦。"]'),
('1527b269-6b29-4ec8-856e-1d15f01e9ba6','丙午新正書懷十首  其二','范成大','宋','宋诗','song-poetry','','[]','瘦骨難勝遇節衣，日高催起趁晨炊。',64,'全唐诗/poet.song.138000.json','["瘦骨難勝遇節衣，日高催起趁晨炊。", "病憐楖栗隨身慣，老覺屠蘇到手遲。", "一飽但蘄庚癸諾，百年甘守甲辰雌。", "莫言此外都無事，柳眼梅梢正索詩。"]'),
('20a22e9c-ca84-42b9-a390-beb17b17ccbc','丙午新正書懷十首  其三','范成大','宋','宋诗','song-poetry','','[]','煮茗燒香了歲時，靜中光景笑中嬉。',64,'全唐诗/poet.song.138000.json','["煮茗燒香了歲時，靜中光景笑中嬉。", "身閒一日似兩日，春淺南枝如北枝。", "朝鏡略無功業到，午窗惟有睡魔知。", "年來并束牀頭易，一任平章濟叔癡。"]'),
('24cd4d01-2bd2-4d15-8e08-2a4d4d0106b0','丙午新正書懷十首  其四','范成大','宋','宋诗','song-poetry','','[]','窮巷閒門本閴然，强將爆竹聒階前。',64,'全唐诗/poet.song.138000.json','["窮巷閒門本閴然，强將爆竹聒階前。", "人情舊雨非今雨，老境增年是減年。", "口不兩匙休足穀，身能幾屐莫言錢。", "掃除一室空諸有，龐老家人總解禪。"]'),
('527e4adf-4f59-48e2-b85a-c6950f1b80f5','丙午新正書懷十首  其五','范成大','宋','宋诗','song-poetry','','[]','厲風翻海雪漫天，百計逃寒息萬緣。',64,'全唐诗/poet.song.138000.json','["厲風翻海雪漫天，百計逃寒息萬緣。", "穩作被爐如卧炕，厚裁綿旋勝披氈。", "尊前現在瞢騰醉，飯後無何爛熳眠。", "斟酌出門高興盡，從教閒却剡溪船。"]'),
('480973df-9e55-4ad6-8895-ef728d7748db','丙午新正書懷十首  其六','范成大','宋','宋诗','song-poetry','','[]','俗情如絮已泥沾，因病偷閒意屬厭。',64,'全唐诗/poet.song.138000.json','["俗情如絮已泥沾，因病偷閒意屬厭。", "鵬鷃相安無可笑，熊魚自古不容兼。", "灰藏榾柮多時暖，雪壓蔓菁滿意甜。", "溫飽閉門吾事辦，異時書判指如籤。"]'),
('6b763ced-21eb-430a-bb36-6d707b1d2bc8','丙午新正書懷十首  其七','范成大','宋','宋诗','song-poetry','','[]','炭熟香濃石鼎煨，人言小閤是春臺。',64,'全唐诗/poet.song.138000.json','["炭熟香濃石鼎煨，人言小閤是春臺。", "蕉心翠展一冬在，梅藟粉融連夜開。", "肅肅九冰妨發育，溫溫三火護恢台。", "養生此外無遺說，梨棗元須趁暖栽。"]'),
('6f349321-a2db-4506-935c-b7fd9e049381','丙午新正書懷十首  其八','范成大','宋','宋诗','song-poetry','','[]','經過掃軌但幽棲，巢穩林深寄一枝。',64,'全唐诗/poet.song.138000.json','["經過掃軌但幽棲，巢穩林深寄一枝。", "栗里歸來窗下卧，香山老去病中詩。", "東風馬耳塵勞後，半夜雞聲睡熟時。", "俯仰平生盡塵迹，恰如腷膊幾枰棋。"]'),
('e2bd5b12-55ad-417c-ad05-24c5a63e185f','丙午新正書懷十首  其九','范成大','宋','宋诗','song-poetry','','[]','窗明窗暗篆煙馡，珍重晨光與夕暉。',64,'全唐诗/poet.song.138000.json','["窗明窗暗篆煙馡，珍重晨光與夕暉。", "東院齋鐘披被坐，南城嚴鼓岸巾歸。", "幾人霜滑騎朝馬，何處燈殘織曉機。", "懶裏若承三昧力，始知忙裏事俱非。"]'),
('b1a3a298-4a4b-4b94-ac10-eeda216c29c3','丙午新正書懷十首  其一○','范成大','宋','宋诗','song-poetry','','[]','殊方節物記吾曾，海北天西一瘦藤。',64,'全唐诗/poet.song.138000.json','["殊方節物記吾曾，海北天西一瘦藤。", "烏欖雞檳嘗老酒，酥花芋葉試新燈。", "瘴雲度嶺濃如墨，邊雪窺窗冷欲冰。", "閒展兩鄉圖畫看，卧遊何必減深登。"]'),
('0073245e-db07-4338-afdc-0288787a07b2','雲露','范成大','宋','宋诗','song-poetry','','[]','飲少嘗遭大戶嗤，病中全是獨醒時。',64,'全唐诗/poet.song.138000.json','["飲少嘗遭大戶嗤，病中全是獨醒時。", "三年魯望自憐賦，萬祀淵明真止詩。", "破戒忽傳雲露法，賞心仍把雪梅枝。", "一杯未問長生事，先罥蛛塵藥裹絲。"]'),
('307d962c-5fee-4b2a-8cbf-df784f4c5d6b','丙午新年六十一歲俗謂之元命作詩自貺','范成大','宋','宋诗','song-poetry','','[]','歲復當生次，星臨本命辰。',144,'全唐诗/poet.song.138000.json','["歲復當生次，星臨本命辰。", "四人同丙午，初度再庚寅。", "長狄名猶記，沙隨會若新。", "童心仍竹馬，暮境忽蒲輪。", "鏡裏全成老，尊前略似春。", "三年歸汶上，千日卧漳濱。", "剛長交新泰，陰消脫舊屯。", "網蛛縈藥裹，竇犬吠醫人。", "窗下烏皮几，田間紫領巾。", "鯢淵方止水，鯤海任揚塵。", "波匿觀河見，維摩示病身。", "顰端還一笑，默識幻中真。"]'),
('cfaf5040-fc6c-41fd-b7be-727d3d00a5fa','丙午人日立春屈指癸卯孟夏晦得疾恰千日矣戲書','范成大','宋','宋诗','song-poetry','','[]','百年能有幾春光，只合都將付醉鄉。',32,'全唐诗/poet.song.138000.json','["百年能有幾春光，只合都將付醉鄉。", "衰病豁除千日外，尚餘三萬五千場。"]'),
('09b84865-1764-4730-a3c5-85380086fd2c','春困二絕  其一','范成大','宋','宋诗','song-poetry','','[]','綵花生菜又新年，節物人情已可憐。',32,'全唐诗/poet.song.138000.json','["綵花生菜又新年，節物人情已可憐。", "不待春來呼我困，四時何日不堪眠。"]'),
('728a8827-422d-41ca-9bc5-b8de0f41d9d2','春困二絕  其二','范成大','宋','宋诗','song-poetry','','[]','諾惺菴裏呼春困，特地回頭著耳聽。',32,'全唐诗/poet.song.138000.json','["諾惺菴裏呼春困，特地回頭著耳聽。", "若解昏昏安穩睡，主翁方始是惺惺。"]'),
('84496aba-660d-4615-86b2-31911571381e','立春大雪招親友共春盤坐上作','范成大','宋','宋诗','song-poetry','','[]','積雪錮萬瓦，雲容如死灰。',144,'全唐诗/poet.song.138000.json','["積雪錮萬瓦，雲容如死灰。", "豈惟梅柳寒，小槽冰春醅。", "東風乃多事，仍將六花來。", "兒女曉翻餠，呵手把一杯。", "菘甲剪翠羽，韭黄㔃金釵。", "齒牙幸牢潔，對案心眼開。", "華年惜節物，況此霜鬢摧。", "如何千日病，三見寅杓回。", "旁人不堪憂，我心猶始孩。", "衰翁豈知道，癡絕忘形骸。", "化兒任惡劇，歡伯有奇懷。", "餘寒會退聽，一笑當安排。"]'),
('9092bb9a-91dd-4563-9f84-b61abacfaa2e','嚴子文以春雪數作用爲瑞不宜多爲韻賦詩見寄次韻','范成大','宋','宋诗','song-poetry','','[]','同雲癡不掃，梅柳春到遲。',120,'全唐诗/poet.song.138000.json','["同雲癡不掃，梅柳春到遲。", "笙歌暖寒會，當任主人爲。", "圍尺庸何傷，袤丈乃非瑞。", "郢中姑度曲，山左已驅癘。", "世無辟寒香，誰能不龜手。", "鄰舍索米歸，衾裯無恙不。", "貧人寒切骨，無地兼無錐。", "安知雙綵勝，但寫入春宜。", "販夫博口食，奈此不售何。", "無術慰啼號，汝今一身多。"]'),
('8d58b260-9125-456d-9e9c-277da5b4ecb0','詠吳中二燈 琉璃毬','范成大','宋','宋诗','song-poetry','','[]','龍綜繅冰繭，魚文鏤玉英。',48,'全唐诗/poet.song.138000.json','["龍綜繅冰繭，魚文鏤玉英。", "雨絲風外縐，雲網日邊明。", "疊暈重重見，分光面面呈。", "不深閒裏趣，爭識箇中情。"]'),
('66d5ffdc-a4c0-47c7-b17e-7ff46efda052','詠吳中二燈 萬眼羅','范成大','宋','宋诗','song-poetry','','[]','弱骨千絲結，輕毬萬錦裝。',48,'全唐诗/poet.song.138000.json','["弱骨千絲結，輕毬萬錦裝。", "綵雲籠月魄，寶氣繞星芒。", "檀點紅嬌小，梅粧粉細香。", "等閒三夕看，消費一年忙。"]'),
('8e3d58e9-f4b9-46ba-888b-4f0190786b53','元夕後連陰','范成大','宋','宋诗','song-poetry','','[]','問訊東風幾日來，冷煙寒霧鎖池臺。',64,'全唐诗/poet.song.138000.json','["問訊東風幾日來，冷煙寒霧鎖池臺。", "掃空積雪翻成雨，收盡殘燈未見梅。", "夜飲厭厭非老伴，春陰漠漠是愁媒。", "誰能腰鼓催花信，快打凉州百面雷。"]'),
('66a831e7-8aee-4ef2-a3d7-398761ef8654','次韻嚴子文見寄','范成大','宋','宋诗','song-poetry','','[]','雨雲濃壓屋山頭，詩句端來寫客憂。',64,'全唐诗/poet.song.138000.json','["雨雲濃壓屋山頭，詩句端來寫客憂。", "雷電已將金薤取，瓊瑶難報木瓜投。", "無心我正銘三住，有意君堪話四休。", "何日尋春同步屧，先教啼鳥說來由。"]'),
('030a7666-138f-4536-b78c-f717cba49acf','再次韻述懷約子文見過','范成大','宋','宋诗','song-poetry','','[]','灰木心形雪滿頭，鶴鳬長短不悲憂。',64,'全唐诗/poet.song.138000.json','["灰木心形雪滿頭，鶴鳬長短不悲憂。", "甕畦純白無機械，蒲局梟盧任博投。", "若愛陶陶并兀兀，先須莫莫與休休。", "箇中情話誰能共，雞黍明當挽仲由。"]'),
('24028d12-4d5a-42e4-b620-7b724142d88b','寄題郫縣蘧仙觀四楠','范成大','宋','宋诗','song-poetry','','[]','沉犀浦上舊仙蹤，老木長春翠掃空。',32,'全唐诗/poet.song.138000.json','["沉犀浦上舊仙蹤，老木長春翠掃空。", "敢請丹光來萬里，爲扶雲嶠駕飛鴻。"]'),
('8554a0d6-fa8a-4695-b1a4-b82403f3dcbe','春來風雨無一日好晴因賦瓶花二絕  其一','范成大','宋','宋诗','song-poetry','','[]','滿插瓶花罷出遊，莫將攀折爲花愁。',32,'全唐诗/poet.song.138000.json','["滿插瓶花罷出遊，莫將攀折爲花愁。", "不知燭照香薰看，何似風吹雨打休。"]'),
('189984f4-7843-4213-8b49-d31eb43ad325','春來風雨無一日好晴因賦瓶花二絕  其二','范成大','宋','宋诗','song-poetry','','[]','酒冷花寒無好懷，柴荆終日爲誰開。',32,'全唐诗/poet.song.138000.json','["酒冷花寒無好懷，柴荆終日爲誰開。", "三分春色三分雨，疋似東風本不來。"]'),
('7f9e4523-a849-4825-a49a-58736e738300','寄題永新張教授無盡藏','范成大','宋','宋诗','song-poetry','','[]','古來誰道四并難，對境心空著處安。',64,'全唐诗/poet.song.138000.json','["古來誰道四并難，對境心空著處安。", "要識見聞無盡藏，先除夢幻有爲觀。", "削平丘垤孤峰峻，撤去籓籬萬象寬。", "快誦老坡秋望賦，大千風月一毫端。"]'),
('c2761e1f-00f2-4e0a-b284-6f31b5c5c13c','寄題莫氏椿桂堂','范成大','宋','宋诗','song-poetry','','[]','君不見衣冠盛事今猶昔，前說燕山後崇德。',67,'全唐诗/poet.song.138000.json','["君不見衣冠盛事今猶昔，前說燕山後崇德。", "聯翩五組带天香，世上籯金賤如礫。", "他年詩禮到雲來，日日高堂稱壽杯。", "桂長孫枝椿不老，却比竇家應更好。"]'),
('3a1ac873-34a1-4d27-af71-99fa6565b53a','春晚即事留游子明王仲顯','范成大','宋','宋诗','song-poetry','','[]','繡地紅千點，平橋綠一篙。',48,'全唐诗/poet.song.138000.json','["繡地紅千點，平橋綠一篙。", "楝花來石首，穀雨熟櫻桃。", "笑我生塵甑，慚君有意袍。", "故人能少駐，門徑久蓬蒿。"]'),
('5b0fe91c-cb84-4dc4-a772-762ae5fadd86','留游子明','范成大','宋','宋诗','song-poetry','','[]','得得跫音喜，匆匆笑口開。',48,'全唐诗/poet.song.138000.json','["得得跫音喜，匆匆笑口開。", "牢愁攻易破，歸夢挽難迴。", "我已疎茶椀，君今減酒杯。", "不知乘興棹，更得幾回來。"]'),
('5fa5e4b9-1b9b-42ce-9ef3-f371214d1222','初夏三絕呈游子明王仲顯  其一','范成大','宋','宋诗','song-poetry','','[]','東君不解惜芳菲，料峭寒中一夢非。',32,'全唐诗/poet.song.138000.json','["東君不解惜芳菲，料峭寒中一夢非。", "剪盡牡丹梅子綻，何須風雨送春歸。"]'),
('f7684a0f-8131-46a1-a964-7c0c8d22dfc9','初夏三絕呈游子明王仲顯  其二','范成大','宋','宋诗','song-poetry','','[]','一簾芳樹綠葱葱，胡蝶飛來覓綺叢。',32,'全唐诗/poet.song.138000.json','["一簾芳樹綠葱葱，胡蝶飛來覓綺叢。", "雪白荼䕷紅寶相，尚携春色見薰風。"]'),
('21863f41-0b34-4f23-8ff4-ace41d26fb8b','初夏三絕呈游子明王仲顯  其三','范成大','宋','宋诗','song-poetry','','[]','送春迎夏未聞雷，日日斜風細雨來。',32,'全唐诗/poet.song.138000.json','["送春迎夏未聞雷，日日斜風細雨來。", "不是故人能裹飯，柴門雖設爲誰開。"]'),
('044c315e-f251-43d3-8f02-2849b942f048','送王仲顯赴瓊筦','范成大','宋','宋诗','song-poetry','','[]','三徑蓬蒿春雨肥，微君誰與開柴扉。',64,'全唐诗/poet.song.138000.json','["三徑蓬蒿春雨肥，微君誰與開柴扉。", "電光射牛書過目，虹氣干斗酒淋衣。", "十年五別歲月老，一方萬里音塵稀。", "誰云滄海斷地脈，莫信天南無鴈飛。"]'),
('a7d89e94-da1c-4590-b464-0d7bd4d31937','梅雨五絕  其一','范成大','宋','宋诗','song-poetry','','[]','梅雨暫收斜照明，去年無此一日晴。',32,'全唐诗/poet.song.138000.json','["梅雨暫收斜照明，去年無此一日晴。", "忽思城東黄篾舫，卧聽打鼓踏車聲。"]'),
('78a3a218-d82c-4522-879d-f2c04d9b31b4','梅雨五絕  其二','范成大','宋','宋诗','song-poetry','','[]','乙酉甲申雷雨驚，乘除却賀芒種晴。',32,'全唐诗/poet.song.138000.json','["乙酉甲申雷雨驚，乘除却賀芒種晴。", "插秧先插蚤秈稻，少忍數旬蒸米成。"]'),
('81b59954-7a84-45ab-abcc-714f41a864b9','梅雨五絕  其三','范成大','宋','宋诗','song-poetry','','[]','風聲不多雨聲多，洶洶曉衾聞浪波。',32,'全唐诗/poet.song.138000.json','["風聲不多雨聲多，洶洶曉衾聞浪波。", "恰似秋眠隠靜寺，玉霄泉從牀下過。"]'),
('d4138e79-6c81-4bab-a58b-9652097c6842','梅雨五絕  其四','范成大','宋','宋诗','song-poetry','','[]','千山雲深甲子雨，十日地濕東南風。',32,'全唐诗/poet.song.138000.json','["千山雲深甲子雨，十日地濕東南風。", "靜裏壺天人不到，火輪飛出默存中。"]'),
('fc9a16c4-1b89-4d17-893d-398e3ee166f2','梅雨五絕  其五','范成大','宋','宋诗','song-poetry','','[]','雨霽雲開池面光，三年魚苗如許長。',32,'全唐诗/poet.song.138000.json','["雨霽雲開池面光，三年魚苗如許長。", "小荷拳拳可包鮓，晚日照盤風露香。"]'),
('d603e9a8-d54d-4970-acf4-f024724567a6','芒種後積雨驟冷三絕  其一','范成大','宋','宋诗','song-poetry','','[]','一菴濕蟄似龜藏，深夏暄寒未可常。',32,'全唐诗/poet.song.138000.json','["一菴濕蟄似龜藏，深夏暄寒未可常。", "昨日蒙絺今挾纊，莫嗔門外有炎凉。"]'),
('967eadd3-7841-4aa0-a7b9-d2440e2a7484','芒種後積雨驟冷三絕  其二','范成大','宋','宋诗','song-poetry','','[]','梅黄時節怯衣單，五月江吳麥秀寒。',32,'全唐诗/poet.song.138000.json','["梅黄時節怯衣單，五月江吳麥秀寒。", "香篆吐雲生暖熱，從教窗外雨漫漫。"]'),
('a99e0f2c-7f27-4554-a933-89d43a38b54c','芒種後積雨驟冷三絕  其三','范成大','宋','宋诗','song-poetry','','[]','梅霖傾瀉九河翻，百瀆交流海面寬。',32,'全唐诗/poet.song.138000.json','["梅霖傾瀉九河翻，百瀆交流海面寬。", "良苦吳農田下濕，年年披絮插秧寒。"]'),
('926fec75-da05-4d34-bd42-92dd86ff240d','東宮壽詩  其一','范成大','宋','宋诗','song-poetry','','[]','再造炎圖撫太寧，龍樓毓德會千齡。',64,'全唐诗/poet.song.138000.json','["再造炎圖撫太寧，龍樓毓德會千齡。", "三宮疊矩深邦本，兩曜重光炳帝庭。", "自古東明陪出日，祇今南極是前星。", "鈞天歲歲家人禮，長對瑶階第四蓂。"]'),
('c9d7bcd6-59b7-4f65-b02b-645e2923d617','東宮壽詩  其二','范成大','宋','宋诗','song-poetry','','[]','並世勳華照古今，朱明綵服侍尊臨。',64,'全唐诗/poet.song.138000.json','["並世勳華照古今，朱明綵服侍尊臨。", "邦家大慶重親養，社稷元良萬國心。", "菊露壺觴秋色正，桂風殿閣月香深。", "欲知天序無疆處，銅律聲中治世音。"]'),
('3d1272df-183b-499f-b896-1c3dad83e704','寄題漢中新作南樓二首  其一','范成大','宋','宋诗','song-poetry','','[]','我作籌邊倚半霄，西山雲雪照弓刀。',32,'全唐诗/poet.song.138000.json','["我作籌邊倚半霄，西山雲雪照弓刀。", "如今且說南樓勝，應共漢壇相對高。"]'),
('b959fd48-63a0-4556-93c2-1a7c3bcc501c','寄題漢中新作南樓二首  其二','范成大','宋','宋诗','song-poetry','','[]','甲子周天事好還，關河響動劍光寒。',32,'全唐诗/poet.song.138000.json','["甲子周天事好還，關河響動劍光寒。", "秦川草木多如薺，時倚樓闌直北看。"]'),
('500acc94-0d5d-47b7-8d76-352ac3905f53','次韻李子永見訪二首  其一','范成大','宋','宋诗','song-poetry','','[]','混俗休超俗，居家似出家。',48,'全唐诗/poet.song.138000.json','["混俗休超俗，居家似出家。", "有爲皆影事，無念即生涯。", "莫覓安心法，翻成揑目花。", "作糜須穀粟，千劫漫炊砂。"]'),
